export const ARTICLES_10: Article[] = [
  { id: 'ccyc-art-1201', lawId: 'codigo-civil-comercial', number: '1201', order: 1201, title: "Conservar la cosa con aptitud para el uso convenido", text: "Conservar la cosa con aptitud para el uso convenido. El locador debe conservar la cosa locada en estado de servir al uso y goce convenido y efectuar a su cargo la reparación que exija el deterioro en su calidad o defecto, originado por cualquier causa no imputable al locatario. En caso de negativa o silencio del locador ante un reclamo del locatario debidamente notificado, para que efectúe alguna reparación urgente, el locatario puede realizar por sí, con cargo al locador, una vez transcurridas al menos veinticuatro (24) horas corridas, contadas a partir de la recepción de la notificación. Si las reparaciones no fueran urgentes, el locatario debe intimar al locador para que realice las mismas dentro de un plazo que no podrá ser inferior a diez (10) días corridos, contados a partir de la recepción de la intimación, cumplido el cual podrá proceder en la forma indicada en el párrafo precedente. En todos los casos, la notificación remitida al domicilio denunciado por el locador en el contrato se tendrá por válida, aun si el locador se negara a recibirla o no pudiese perfeccionarse por motivos imputables al mismo. (Artículo sustituido por art. 3º de la Ley Nº 27.737 B.O. 17/10/2023. Vigencia: a partir del día siguiente al de su publicación en el Boletín Oficial y resultará de aplicación para los ejercicios fiscales 2023 y siguientes.)", plainLanguageExplanation: "Establece el régimen de conservar la cosa con aptitud para el uso convenido. El locador debe conservar la cosa locada en estado de servir al uso y goce convenido y efectuar a su cargo la reparación que exija el deterioro en su calidad o defecto, originado por cualquier causa no imputable al locatario.", practicalEffects: ['En la práctica, este artículo rige conservar la cosa con aptitud para el uso convenido. El locador debe conservar la cosa locada en estado de servir al uso y goce convenido y efectuar a su cargo la reparación que exija el deterioro en su'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conservar', 'cosa', 'aptitud', 'para', 'convenido', 'articulo 1201'], segments: [], amendments: [] },
  { id: 'ccyc-art-1202', lawId: 'codigo-civil-comercial', number: '1202', order: 1202, title: "Artículo derogado por art", text: "Artículo derogado por art. 258 del Decreto N° 70/2023 B.O. 21/12/2023)", plainLanguageExplanation: "Establece el régimen de artículo derogado por art. 258 del Decreto N° 70/2023 B.O.", practicalEffects: ['En la práctica, este artículo rige artículo derogado por art. 258 del Decreto N° 70/2023 B.O.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['artculo', 'derogado', 'articulo 1202'], segments: [], amendments: [] },
  { id: 'ccyc-art-1203', lawId: 'codigo-civil-comercial', number: '1203', order: 1203, title: "Frustración del uso o goce de la cosa", text: "Frustración del uso o goce de la cosa. Si por causas no imputables al locatario, éste se ve impedido de usar o gozar de la cosa, o ésta no puede servir para el objeto de la convención, puede pedir la rescisión del contrato, o la cesación del pago del precio por el tiempo que no pueda usar o gozar de la cosa. Si no se viese afectada directa o indirectamente la cosa misma, sus obligaciones continúan como antes. (Artículo sustituido por art. 6º de la Ley Nº 27.551 B.O. 30/6/2020. Vigencia: a partir del día siguiente al de su publicación en el Boletín Oficial de la República Argentina y serán aplicables para los contratos que se celebren a partir de su entrada en vigencia. Ley N° 27.551 abrogada por art. 249 del Decreto N° 70/2023 B.O. 27/12/2023 )", plainLanguageExplanation: "Establece el régimen de frustración del uso o goce de la cosa. Si por causas no imputables al locatario, éste se ve impedido de usar o gozar de la cosa, o ésta no puede servir para el objeto de la convención, puede pedir la rescisión del contrato, o la cesación del pago del precio por el tiempo que no pueda usar o gozar de la cosa.", practicalEffects: ['En la práctica, este artículo rige frustración del uso o goce de la cosa. Si por causas no imputables al locatario, éste se ve impedido de usar o gozar de la cosa, o ésta no puede servir para el objeto de la convención, pued'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['frustracin', 'goce', 'cosa', 'articulo 1203'], segments: [], amendments: [] },
  { id: 'ccyc-art-1204', lawId: 'codigo-civil-comercial', number: '1204', order: 1204, title: "Artículo derogado por art", text: "Artículo derogado por art. 259 del Decreto N° 70/2023 B.O. 21/12/2023) ARTICULO 1204 bis.- (Artículo derogado por art. 259 del Decreto N° 70/2023 B.O. 21/12/2023) Parágrafo 2° Obligaciones del locatario", plainLanguageExplanation: "Establece el régimen de artículo derogado por art. 259 del Decreto N° 70/2023 B.O.", practicalEffects: ['En la práctica, este artículo rige artículo derogado por art. 259 del Decreto N° 70/2023 B.O.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['artculo', 'derogado', 'articulo 1204'], segments: [], amendments: [] },
  { id: 'ccyc-art-1205', lawId: 'codigo-civil-comercial', number: '1205', order: 1205, title: "Prohibición de variar el destino", text: "Prohibición de variar el destino. El locatario puede usar y gozar de la cosa conforme a derecho y exclusivamente para el destino correspondiente. No puede variarlo aunque ello no cause perjuicio al locador.", plainLanguageExplanation: "Establece el régimen de prohibición de variar el destino. El locatario puede usar y gozar de la cosa conforme a derecho y exclusivamente para el destino correspondiente.", practicalEffects: ['En la práctica, este artículo rige prohibición de variar el destino. El locatario puede usar y gozar de la cosa conforme a derecho y exclusivamente para el destino correspondiente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibicin', 'variar', 'destino', 'articulo 1205'], segments: [], amendments: [] },
  { id: 'ccyc-art-1206', lawId: 'codigo-civil-comercial', number: '1206', order: 1206, title: "Conservar la cosa en buen estado", text: "Conservar la cosa en buen estado. Destrucción. El locatario debe mantener la cosa y conservarla en el estado en que la recibió. No cumple con esta obligación si la abandona sin dejar quien haga sus veces. Responde por cualquier deterioro causado a la cosa, incluso por visitantes ocasionales, pero no por acción del locador o sus dependientes; asimismo responde por la destrucción de la cosa por incendio no originado en caso fortuito.", plainLanguageExplanation: "Establece el régimen de conservar la cosa en buen estado. Destrucción.", practicalEffects: ['En la práctica, este artículo rige conservar la cosa en buen estado. Destrucción.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conservar', 'cosa', 'buen', 'estado', 'articulo 1206'], segments: [], amendments: [] },
  { id: 'ccyc-art-1207', lawId: 'codigo-civil-comercial', number: '1207', order: 1207, title: "Mantener la cosa en buen estado", text: "Mantener la cosa en buen estado. Reparaciones. Si la cosa es mueble, el locatario tiene a su cargo el gasto de su conservación y las mejoras de mero mantenimiento; y sólo éstas si es inmueble. Si es urgente realizar reparaciones necesarias puede efectuarlas a costa del locador dándole aviso previo.", plainLanguageExplanation: "Establece el régimen de mantener la cosa en buen estado. Reparaciones.", practicalEffects: ['En la práctica, este artículo rige mantener la cosa en buen estado. Reparaciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mantener', 'cosa', 'buen', 'estado', 'articulo 1207'], segments: [], amendments: [] },
  { id: 'ccyc-art-1208', lawId: 'codigo-civil-comercial', number: '1208', order: 1208, title: "Pagar el canon convenido", text: "Pagar el canon convenido. La prestación dineraria a cargo del locatario se integra con el precio de la locación y toda otra prestación de pago periódico asumida convencionalmente por el locatario. Para su cobro se concede vía ejecutiva. A falta de convención, el pago debe ser hecho por anticipado: si la cosa es mueble, de contado; y si es inmueble, por período mensual.", plainLanguageExplanation: "Establece el régimen de pagar el canon convenido. La prestación dineraria a cargo del locatario se integra con el precio de la locación y toda otra prestación de pago periódico asumida convencionalmente por el locatario.", practicalEffects: ['En la práctica, este artículo rige pagar el canon convenido. La prestación dineraria a cargo del locatario se integra con el precio de la locación y toda otra prestación de pago periódico asumida convencionalmente por el locatario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pagar', 'canon', 'convenido', 'articulo 1208'], segments: [], amendments: [] },
  { id: 'ccyc-art-1209', lawId: 'codigo-civil-comercial', number: '1209', order: 1209, title: "Pagar cargas y contribuciones por la actividad", text: "Pagar cargas y contribuciones por la actividad. El locatario tiene a su cargo el pago de las cargas y contribuciones que se originen en el destino que dé a la cosa locada. No tiene a su cargo el pago de las que graven la cosa ni las expensas comunes extraordinarias. Solo puede establecerse que estén a cargo del locatario aquellas expensas que deriven de gastos habituales, entendiéndose por tales aquellos que se vinculan a los servicios normales y permanentes a disposición del locatario, independientemente de que sean considerados como expensas comunes ordinarias o extraordinarias. (Artículo sustituido por art. 8º de la Ley Nº 27.551 B.O. 30/6/2020. Vigencia: a partir del día siguiente al de su publicación en el Boletín Oficial de la República Argentina y serán aplicables para los contratos que se celebren a partir de su entrada en vigencia. Ley N° 27.551 abrogada por art. 249 del Decreto N° 70/2023 B.O. 27/12/2023)", plainLanguageExplanation: "Establece el régimen de pagar cargas y contribuciones por la actividad. El locatario tiene a su cargo el pago de las cargas y contribuciones que se originen en el destino que dé a la cosa locada.", practicalEffects: ['En la práctica, este artículo rige pagar cargas y contribuciones por la actividad. El locatario tiene a su cargo el pago de las cargas y contribuciones que se originen en el destino que dé a la cosa locada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pagar', 'cargas', 'contribuciones', 'actividad', 'articulo 1209'], segments: [], amendments: [] },
  { id: 'ccyc-art-1210', lawId: 'codigo-civil-comercial', number: '1210', order: 1210, title: "Restituir la cosa", text: "Restituir la cosa. El locatario, al concluir el contrato, debe restituir al locador la cosa en el estado en que la recibió, excepto los deterioros provenientes del mero transcurso del tiempo y el uso regular. También debe entregarle las constancias de los pagos que efectuó en razón de la relación locativa y que resulten atinentes a la cosa o a los servicios que tenga. Parágrafo 3° Régimen de mejoras", plainLanguageExplanation: "Establece el régimen de restituir la cosa. El locatario, al concluir el contrato, debe restituir al locador la cosa en el estado en que la recibió, excepto los deterioros provenientes del mero transcurso del tiempo y el uso regular.", practicalEffects: ['En la práctica, este artículo rige restituir la cosa. El locatario, al concluir el contrato, debe restituir al locador la cosa en el estado en que la recibió, excepto los deterioros provenientes del mero transcurso del tiempo y el uso regular.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['restituir', 'cosa', 'articulo 1210'], segments: [], amendments: [] },
  { id: 'ccyc-art-1211', lawId: 'codigo-civil-comercial', number: '1211', order: 1211, title: "Regla", text: "Regla. El locatario puede realizar mejoras en la cosa locada, excepto que esté prohibido en el contrato, alteren la substancia o forma de la cosa, o haya sido interpelado a restituirla. No tiene derecho a reclamar el pago de mejoras útiles y de mero lujo o suntuarias, pero, si son mejoras necesarias, puede reclamar su valor al locador.", plainLanguageExplanation: "Establece el régimen de regla. El locatario puede realizar mejoras en la cosa locada, excepto que esté prohibido en el contrato, alteren la substancia o forma de la cosa, o haya sido interpelado a restituirla.", practicalEffects: ['En la práctica, este artículo rige regla. El locatario puede realizar mejoras en la cosa locada, excepto que esté prohibido en el contrato, alteren la substancia o forma de la cosa, o haya sido interpelado a restituirla.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglaarticulo 1211'], segments: [], amendments: [] },
  { id: 'ccyc-art-1212', lawId: 'codigo-civil-comercial', number: '1212', order: 1212, title: "Violación al régimen de mejoras", text: "Violación al régimen de mejoras. La realización de mejoras prohibidas en el artículo 1211 viola la obligación de conservar la cosa en el estado en que se recibió. SECCION 5ª Cesión y sublocación", plainLanguageExplanation: "Establece el régimen de violación al régimen de mejoras. La realización de mejoras prohibidas en el artículo 1211 viola la obligación de conservar la cosa en el estado en que se recibió.", practicalEffects: ['En la práctica, este artículo rige violación al régimen de mejoras. La realización de mejoras prohibidas en el artículo 1211 viola la obligación de conservar la cosa en el estado en que se recibió.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['violacin', 'rgimen', 'mejoras', 'articulo 1212'], segments: [], amendments: [] },
  { id: 'ccyc-art-1213', lawId: 'codigo-civil-comercial', number: '1213', order: 1213, title: "Cesión", text: "Cesión. El locatario sólo puede ceder su posición contractual en los términos previstos en los artículos 1636 y siguientes. La cesión que no reúna tales requisitos viola la prohibición de variar el destino de la cosa locada. La prohibición contractual de ceder importa la de sublocar y viceversa. Se considera cesión a la sublocación de toda la cosa.", plainLanguageExplanation: "Establece el régimen de cesión. El locatario sólo puede ceder su posición contractual en los términos previstos en los artículos 1636 y siguientes.", practicalEffects: ['En la práctica, este artículo rige cesión. El locatario sólo puede ceder su posición contractual en los términos previstos en los artículos 1636 y siguientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cesinarticulo 1213'], segments: [], amendments: [] },
  { id: 'ccyc-art-1214', lawId: 'codigo-civil-comercial', number: '1214', order: 1214, title: "Sublocación", text: "Sublocación. El locatario puede dar en sublocación parte de la cosa locada, si no hay pacto en contrario. Para ello debe comunicar al locador, por medio fehaciente, su intención de sublocar e indicarle el nombre y domicilio de la persona con quien se propone contratar, y el destino que el sublocatario asignará a la cosa. El locador sólo puede oponerse por medio fehaciente, dentro del plazo de diez días de notificado. El silencio del locador importa su conformidad con la sublocación propuesta. La sublocación contratada pese la oposición del locador, o con apartamiento de los términos que se le comunicaron, viola la prohibición de variar el destino de la cosa locada.", plainLanguageExplanation: "Establece el régimen de sublocación. El locatario puede dar en sublocación parte de la cosa locada, si no hay pacto en contrario.", practicalEffects: ['En la práctica, este artículo rige sublocación. El locatario puede dar en sublocación parte de la cosa locada, si no hay pacto en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sublocacinarticulo 1214'], segments: [], amendments: [] },
  { id: 'ccyc-art-1215', lawId: 'codigo-civil-comercial', number: '1215', order: 1215, title: "Relaciones entre sublocador y sublocatario", text: "Relaciones entre sublocador y sublocatario. Entre sublocador y sublocatario rigen las normas previstas en el contrato respectivo y las de este Capítulo. Está implícita la cláusula de usar y gozar de la cosa sin transgredir el contrato principal.", plainLanguageExplanation: "Establece el régimen de relaciones entre sublocador y sublocatario. Entre sublocador y sublocatario rigen las normas previstas en el contrato respectivo y las de este Capítulo.", practicalEffects: ['En la práctica, este artículo rige relaciones entre sublocador y sublocatario. Entre sublocador y sublocatario rigen las normas previstas en el contrato respectivo y las de este Capítulo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['relaciones', 'entre', 'sublocador', 'sublocatario', 'articulo 1215'], segments: [], amendments: [] },
  { id: 'ccyc-art-1216', lawId: 'codigo-civil-comercial', number: '1216', order: 1216, title: "Acciones directas", text: "Acciones directas. Sin perjuicio de sus derechos respecto al locatario, el locador tiene acción directa contra el sublocatario para cobrar el alquiler adeudado por el locatario, en la medida de la deuda del sublocatario. También puede exigir de éste el cumplimiento de las obligaciones que la sublocación le impone, inclusive el resarcimiento de los daños causados por uso indebido de la cosa. Recíprocamente, el sublocatario tiene acción directa contra el locador para obtener a su favor el cumplimiento de las obligaciones asumidas en el contrato de locación. La conclusión de la locación determina la cesación del subarriendo, excepto que se haya producido por confusión. SECCION 6ª Extinción", plainLanguageExplanation: "Establece el régimen de acciones directas. Sin perjuicio de sus derechos respecto al locatario, el locador tiene acción directa contra el sublocatario para cobrar el alquiler adeudado por el locatario, en la medida de la deuda del sublocatario.", practicalEffects: ['En la práctica, este artículo rige acciones directas. Sin perjuicio de sus derechos respecto al locatario, el locador tiene acción directa contra el sublocatario para cobrar el alquiler adeudado por el lo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acciones', 'directas', 'articulo 1216'], segments: [], amendments: [] },
  { id: 'ccyc-art-1217', lawId: 'codigo-civil-comercial', number: '1217', order: 1217, title: "Extinción de la locación", text: "Extinción de la locación. Son modos especiales de extinción de la locación: a) el cumplimiento del plazo convenido, o requerimiento previsto en el artículo 1218, según el caso; b) la resolución anticipada.", plainLanguageExplanation: "Establece el régimen de extinción de la locación. Son modos especiales de extinción de la locación: a) el cumplimiento del plazo convenido, o requerimiento previsto en el artículo 1218, según el caso; b) la resolución anticipada.", practicalEffects: ['En la práctica, este artículo rige extinción de la locación. Son modos especiales de extinción de la locación: a) el cumplimiento del plazo convenido, o requerimiento previsto en el artículo 1218, según el caso;'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'locacin', 'articulo 1217'], segments: [], amendments: [] },
  { id: 'ccyc-art-1218', lawId: 'codigo-civil-comercial', number: '1218', order: 1218, title: "Continuación de la locación concluida", text: "Continuación de la locación concluida. Si vence el plazo convenido o el plazo mínimo legal en ausencia de convención, y el locatario continúa en la tenencia de la cosa, no hay tácita reconducción, sino la continuación de la locación en los mismos términos contratados, hasta que cualquiera de las partes dé por concluido el contrato mediante comunicación fehaciente. La recepción de pagos durante la continuación de la locación no altera lo dispuesto en el primer párrafo.", plainLanguageExplanation: "Establece el régimen de continuación de la locación concluida. Si vence el plazo convenido o el plazo mínimo legal en ausencia de convención, y el locatario continúa en la tenencia de la cosa, no hay tácita reconducción, sino la continuación de la locación en los mismos términos contratados, hasta que cualquiera de las partes dé por concluid", practicalEffects: ['En la práctica, este artículo rige continuación de la locación concluida. Si vence el plazo convenido o el plazo mínimo legal en ausencia de convención, y el locatario continúa en la tenencia de la cosa, no hay tácita recond'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['continuacin', 'locacin', 'concluida', 'articulo 1218'], segments: [], amendments: [] },
  { id: 'ccyc-art-1219', lawId: 'codigo-civil-comercial', number: '1219', order: 1219, title: "Resolución imputable al locatario", text: "Resolución imputable al locatario. El locador puede resolver el contrato: a) por cambio de destino o uso irregular en los términos del artículo 1205; b) por falta de conservación de la cosa locada, o su abandono sin dejar quien haga sus veces; c) por falta de pago de la prestación dineraria convenida, durante dos períodos consecutivos. d) por cualquier causa fijada en el contrato. (Inciso incorporado por art. 260 del Decreto N° 70/2023 B.O. 21/12/2023)", plainLanguageExplanation: "Establece el régimen de resolución imputable al locatario. El locador puede resolver el contrato: a) por cambio de destino o uso irregular en los términos del artículo 1205; b) por falta de conservación de la cosa locada, o su abandono sin dejar quien haga sus veces; c) por falta de pago de la prestación dineraria convenida, durante dos", practicalEffects: ['En la práctica, este artículo rige resolución imputable al locatario. El locador puede resolver el contrato: a) por cambio de destino o uso irregular en los términos del artículo 1205; b) por falta de conservación de la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resolucin', 'imputable', 'locatario', 'articulo 1219'], segments: [], amendments: [] },
  { id: 'ccyc-art-1220', lawId: 'codigo-civil-comercial', number: '1220', order: 1220, title: "Resolución imputable al locador", text: "Resolución imputable al locador. El locatario puede resolver el contrato si el locador incumple: a) la obligación de conservar la cosa con aptitud para el uso y goce convenido, salvo cuando el daño haya sido ocasionado directa o indirectamente por el locatario; b) la garantía de evicción o la de vicios redhibitorios. (Artículo sustituido por art. 261 del Decreto N° 70/2023 B.O. 21/12/2023)", plainLanguageExplanation: "Establece el régimen de resolución imputable al locador. El locatario puede resolver el contrato si el locador incumple: a) la obligación de conservar la cosa con aptitud para el uso y goce convenido, salvo cuando el daño haya sido ocasionado directa o indirectamente por el locatario; b) la garantía de evicción o la de vicios redhibitorios.", practicalEffects: ['En la práctica, este artículo rige resolución imputable al locador. El locatario puede resolver el contrato si el locador incumple: a) la obligación de conservar la cosa con aptitud para el uso y goce convenido, salvo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resolucin', 'imputable', 'locador', 'articulo 1220'], segments: [], amendments: [] },
  { id: 'ccyc-art-1221', lawId: 'codigo-civil-comercial', number: '1221', order: 1221, title: "Resolución anticipada", text: "Resolución anticipada. El locatario podrá, en cualquier momento, resolver la contratación abonando el equivalente al diez por ciento (10%) del saldo del canon locativo futuro, calculado desde la fecha de la notificación de la rescisión hasta la fecha de finalización pactada en el contrato. (Artículo sustituido por art. 262 del Decreto N° 70/2023 B.O. 21/12/2023) ARTICULO 1221 bis.- (Artículo derogado por art. 263 del Decreto N° 70/2023 B.O. 21/12/2023) SECCION 7ª Efectos de la extinción", plainLanguageExplanation: "Establece el régimen de resolución anticipada. El locatario podrá, en cualquier momento, resolver la contratación abonando el equivalente al diez por ciento (10%) del saldo del canon locativo futuro, calculado desde la fecha de la notificación de la rescisión hasta la fecha de finalización pactada en el contrato.", practicalEffects: ['En la práctica, este artículo rige resolución anticipada. El locatario podrá, en cualquier momento, resolver la contratación abonando el equivalente al diez por ciento (10%) del saldo del canon locativo futur'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resolucin', 'anticipada', 'articulo 1221'], segments: [], amendments: [] },
  { id: 'ccyc-art-1222', lawId: 'codigo-civil-comercial', number: '1222', order: 1222, title: "Intimación de pago y desalojo de viviendas", text: "Intimación de pago y desalojo de viviendas. Si el destino es habitacional, previamente a la demanda de desalojo por falta de pago de alquileres, el locador debe intimar fehacientemente al locatario al pago de la cantidad debida, otorgando para ello un plazo que nunca debe ser inferior a diez (10) días corridos contados a partir de la recepción de la intimación, especificando el lugar de pago. La notificación remitida al domicilio denunciado en el contrato por el locatario se tiene por válida, aun si éste se negara a recibirla o no pudiese perfeccionarse por motivos imputables al mismo. Cumplido el plazo previsto en el primer párrafo de este artículo, o habiéndose verificado la extinción de la locación por cualquier motivo, el locatario debe restituir la tenencia del inmueble locado. Ante el incumplimiento del locatario, el locador puede iniciar la acción judicial de desalojo, la que debe sustanciarse por el proceso previsto al efecto en cada jurisdicción y en caso de no prever un procedimiento especial, el más abreviado que establezcan sus leyes procesales o especiales. En ningún caso el locador puede negarse a recibir las llaves del inmueble o condicionar la misma, sin perjuicio de la reserva por las obligaciones pendientes a cargo del locatario. En caso de negativa o silencio frente al requerimiento por parte del inquilino a efectos de que se le reciba la llave del inmueble, éste puede realizar la consignación judicial de las mismas, siendo los gastos y costas a cargo del locador. En ningún caso se adeudarán alquileres ni ningún tipo de obligación accesoria a partir del día de la notificación fehaciente realizada al locador a efectos de que reciba las llaves del inmueble, siempre que el locatario efectúe la consignación judicial dentro de los diez (10) días hábiles siguientes a la misma, o desde que le fuera notificado al locador el depósito judicial de la llave si la consignación se hubiese iniciado después del vencimiento de dicho plazo. (Artículo sustituido por art. 11 de la Ley Nº 27.551 B.O. 30/6/2020. Vigencia: a partir del día siguiente al de su publicación en el Boletín Oficial de la República Argentina y serán aplicables para los contratos que se celebren a partir de su entrada en vigencia. Ley N° 27.551 abrogada por art. 249 del Decreto N° 70/2023 B.O. 27/12/2023)", plainLanguageExplanation: "Establece el régimen de intimación de pago y desalojo de viviendas. Si el destino es habitacional, previamente a la demanda de desalojo por falta de pago de alquileres, el locador debe intimar fehacientemente al locatario al pago de la cantidad debida, otorgando para ello un plazo que nunca debe ser inferior a diez (10) días corridos contados a p", practicalEffects: ['En la práctica, este artículo rige intimación de pago y desalojo de viviendas. Si el destino es habitacional, previamente a la demanda de desalojo por falta de pago de alquileres, el locador debe intimar fehacientemente al locata'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intimacin', 'pago', 'desalojo', 'viviendas', 'articulo 1222'], segments: [], amendments: [] },
  { id: 'ccyc-art-1223', lawId: 'codigo-civil-comercial', number: '1223', order: 1223, title: "Desalojo", text: "Desalojo. Al extinguirse la locación debe restituirse la tenencia de la cosa locada. El procedimiento previsto en este Código para la cláusula resolutoria implícita no se aplica a la demanda de desalojo por las causas de los artículos 1217 y 1219, inciso c). El plazo de ejecución de la sentencia de desalojo no puede ser menor a diez días.", plainLanguageExplanation: "Establece el régimen de desalojo. Al extinguirse la locación debe restituirse la tenencia de la cosa locada.", practicalEffects: ['En la práctica, este artículo rige desalojo. Al extinguirse la locación debe restituirse la tenencia de la cosa locada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desalojoarticulo 1223'], segments: [], amendments: [] },
  { id: 'ccyc-art-1224', lawId: 'codigo-civil-comercial', number: '1224', order: 1224, title: "Facultades sobre las mejoras útiles o suntuarias", text: "Facultades sobre las mejoras útiles o suntuarias. El locatario puede retirar la mejora útil o suntuaria al concluir la locación; pero no puede hacerlo si acordó que quede en beneficio de la cosa, si de la separación se sigue daño para ella, o separarla no le ocasiona provecho alguno. El locador puede adquirir la mejora hecha en violación a una prohibición contractual, pagando el mayor valor que adquirió la cosa.", plainLanguageExplanation: "Establece el régimen de facultades sobre las mejoras útiles o suntuarias. El locatario puede retirar la mejora útil o suntuaria al concluir la locación; pero no puede hacerlo si acordó que quede en beneficio de la cosa, si de la separación se sigue daño para ella, o separarla no le ocasiona provecho alguno.", practicalEffects: ['En la práctica, este artículo rige facultades sobre las mejoras útiles o suntuarias. El locatario puede retirar la mejora útil o suntuaria al concluir la locación; pero no puede hacerlo si acordó que quede en beneficio de la cosa, si d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultades', 'sobre', 'mejoras', 'tiles', 'suntuarias', 'articulo 1224'], segments: [], amendments: [] },
  { id: 'ccyc-art-1225', lawId: 'codigo-civil-comercial', number: '1225', order: 1225, title: "Caducidad de la fianza", text: "Caducidad de la fianza. Renovación. Las obligaciones del fiador cesan automáticamente al vencimiento del plazo de la locación, excepto la que derive de la no restitución en tiempo del inmueble locado. Se exige el consentimiento expreso del fiador para obligarse en la renovación o prórroga expresa o tácita, una vez vencido el plazo del contrato de locación. Es nula toda disposición anticipada que extienda la fianza, sea simple, solidaria como codeudor o principal pagador, del contrato de locación original.", plainLanguageExplanation: "Establece el régimen de caducidad de la fianza. Renovación.", practicalEffects: ['En la práctica, este artículo rige caducidad de la fianza. Renovación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caducidad', 'fianza', 'articulo 1225'], segments: [], amendments: [] },
  { id: 'ccyc-art-1226', lawId: 'codigo-civil-comercial', number: '1226', order: 1226, title: "Facultad de retención", text: "Facultad de retención. El ejercicio del derecho de retención por el locatario lo faculta a percibir los frutos naturales que la cosa produzca. Si lo hace, al momento de la percepción debe compensar ese valor con la suma que le es debida. CAPITULO 5 Leasing", plainLanguageExplanation: "Establece el régimen de facultad de retención. El ejercicio del derecho de retención por el locatario lo faculta a percibir los frutos naturales que la cosa produzca.", practicalEffects: ['En la práctica, este artículo rige facultad de retención. El ejercicio del derecho de retención por el locatario lo faculta a percibir los frutos naturales que la cosa produzca.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultad', 'retencin', 'articulo 1226'], segments: [], amendments: [] },
  { id: 'ccyc-art-1227', lawId: 'codigo-civil-comercial', number: '1227', order: 1227, title: "Concepto", text: "Concepto. En el contrato de leasing el dador conviene transferir al tomador la tenencia de un bien cierto y determinado para su uso y goce, contra el pago de un canon y le confiere una opción de compra por un precio.", plainLanguageExplanation: "Establece el régimen de concepto. En el contrato de leasing el dador conviene transferir al tomador la tenencia de un bien cierto y determinado para su uso y goce, contra el pago de un canon y le confiere una opción de compra por un precio.", practicalEffects: ['En la práctica, este artículo rige concepto. En el contrato de leasing el dador conviene transferir al tomador la tenencia de un bien cierto y determinado para su uso y goce, contra el pago de un'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 1227'], segments: [], amendments: [] },
  { id: 'ccyc-art-1228', lawId: 'codigo-civil-comercial', number: '1228', order: 1228, title: "Objeto", text: "Objeto. Pueden ser objeto del contrato cosas muebles e inmuebles, marcas, patentes o modelos industriales y software, de propiedad del dador o sobre los que el dador tenga la facultad de dar en leasing.", plainLanguageExplanation: "Establece el régimen de objeto. Pueden ser objeto del contrato cosas muebles e inmuebles, marcas, patentes o modelos industriales y software, de propiedad del dador o sobre los que el dador tenga la facultad de dar en leasing.", practicalEffects: ['En la práctica, este artículo rige objeto. Pueden ser objeto del contrato cosas muebles e inmuebles, marcas, patentes o modelos industriales y software, de propiedad del dador o sobre los que e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['objetoarticulo 1228'], segments: [], amendments: [] },
  { id: 'ccyc-art-1229', lawId: 'codigo-civil-comercial', number: '1229', order: 1229, title: "Canon", text: "Canon. El monto y la periodicidad de cada canon se determina convencionalmente.", plainLanguageExplanation: "Establece el régimen de canon. El monto y la periodicidad de cada canon se determina convencionalmente.", practicalEffects: ['En la práctica, este artículo rige canon. El monto y la periodicidad de cada canon se determina convencionalmente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['canonarticulo 1229'], segments: [], amendments: [] },
  { id: 'ccyc-art-1230', lawId: 'codigo-civil-comercial', number: '1230', order: 1230, title: "Precio de ejercicio de la opción", text: "Precio de ejercicio de la opción. El precio de ejercicio de la opción de compra debe estar fijado en el contrato o ser determinable según procedimientos o pautas pactadas.", plainLanguageExplanation: "Establece el régimen de precio de ejercicio de la opción. El precio de ejercicio de la opción de compra debe estar fijado en el contrato o ser determinable según procedimientos o pautas pactadas.", practicalEffects: ['En la práctica, este artículo rige precio de ejercicio de la opción. El precio de ejercicio de la opción de compra debe estar fijado en el contrato o ser determinable según procedimientos o pautas pactadas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['precio', 'ejercicio', 'opcin', 'articulo 1230'], segments: [], amendments: [] },
  { id: 'ccyc-art-1231', lawId: 'codigo-civil-comercial', number: '1231', order: 1231, title: "Modalidades en la elección del bien", text: "Modalidades en la elección del bien. El bien objeto del contrato puede: a) comprarse por el dador a persona indicada por el tomador; b) comprarse por el dador según especificaciones del tomador o según catálogos, folletos o descripciones identificadas por éste; c) comprarse por el dador, quien sustituye al tomador, al efecto, en un contrato de compraventa que éste haya celebrado; d) ser de propiedad del dador con anterioridad a su vinculación contractual con el tomador; e) adquirirse por el dador al tomador por el mismo contrato o habérselo adquirido con anterioridad; f) estar a disposición jurídica del dador por título que le permita constituir leasing sobre él.", plainLanguageExplanation: "Establece el régimen de modalidades en la elección del bien. El bien objeto del contrato puede: a) comprarse por el dador a persona indicada por el tomador; b) comprarse por el dador según especificaciones del tomador o según catálogos, folletos o descripciones identificadas por éste; c) comprarse por el dador, quien sustituye al tomador,", practicalEffects: ['En la práctica, este artículo rige modalidades en la elección del bien. El bien objeto del contrato puede: a) comprarse por el dador a persona indicada por el tomador; b) comprarse por el dador según especificaciones del t'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modalidades', 'eleccin', 'bien', 'articulo 1231'], segments: [], amendments: [] },
  { id: 'ccyc-art-1232', lawId: 'codigo-civil-comercial', number: '1232', order: 1232, title: "Responsabilidades, acciones y garantías en la adquisición del bien", text: "Responsabilidades, acciones y garantías en la adquisición del bien. En los casos de los incisos a), b) y c) del artículo 1231, el dador cumple el contrato adquiriendo los bienes indicados por el tomador. El tomador puede reclamar del vendedor, sin necesidad de cesión, todos los derechos que emergen del contrato de compraventa. El dador puede liberarse convencionalmente de las responsabilidades de entrega y de la obligación de saneamiento. En los casos del inciso d) del artículo 1231, así como en aquellos casos en que el dador es fabricante, importador, vendedor o constructor del bien dado en leasing, el dador no puede liberarse de la obligación de entrega y de la obligación de saneamiento. En los casos del inciso e) del mismo artículo, el dador no responde por la obligación de entrega ni por garantía de saneamiento, excepto pacto en contrario. En los casos del inciso f) se deben aplicar las reglas de los párrafos anteriores de este artículo, según corresponda a la situación concreta.", plainLanguageExplanation: "Establece el régimen de responsabilidades, acciones y garantías en la adquisición del bien. En los casos de los incisos a), b) y c) del artículo 1231, el dador cumple el contrato adquiriendo los bienes indicados por el tomador.", practicalEffects: ['En la práctica, este artículo rige responsabilidades, acciones y garantías en la adquisición del bien. En los casos de los incisos a), b) y c) del artículo 1231, el dador cumple el contrato adquiriendo los bienes indicados por el tomador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidades', 'acciones', 'garantas', 'adquisicin', 'bien', 'articulo 1232'], segments: [], amendments: [] },
  { id: 'ccyc-art-1233', lawId: 'codigo-civil-comercial', number: '1233', order: 1233, title: "Servicios y accesorios", text: "Servicios y accesorios. Pueden incluirse en el contrato los servicios y accesorios necesarios para el diseño, la instalación, puesta en marcha y puesta a disposición de los bienes dados en leasing, y su precio integrar el cálculo del canon.", plainLanguageExplanation: "Establece el régimen de servicios y accesorios. Pueden incluirse en el contrato los servicios y accesorios necesarios para el diseño, la instalación, puesta en marcha y puesta a disposición de los bienes dados en leasing, y su precio integrar el cálculo del canon.", practicalEffects: ['En la práctica, este artículo rige servicios y accesorios. Pueden incluirse en el contrato los servicios y accesorios necesarios para el diseño, la instalación, puesta en marcha y puesta a disposición de los b'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['servicios', 'accesorios', 'articulo 1233'], segments: [], amendments: [] },
  { id: 'ccyc-art-1234', lawId: 'codigo-civil-comercial', number: '1234', order: 1234, title: "Forma e inscripción", text: "Forma e inscripción. El leasing debe instrumentarse en escritura pública si tiene como objeto inmuebles, buques o aeronaves. En los demás casos puede celebrarse por instrumento público o privado. A los efectos de su oponibilidad frente a terceros, el contrato debe inscribirse en el registro que corresponda según la naturaleza de la cosa que constituye su objeto. La inscripción en el registro puede efectuarse a partir de la celebración del contrato de leasing, y con prescindencia de la fecha en que corresponda hacer entrega de la cosa objeto de la prestación comprometida. Para que produzca efectos contra terceros desde la entrega del bien objeto del leasing, la inscripción debe solicitarse dentro de los cinco días hábiles posteriores. Pasado ese término, produce ese efecto desde que el contrato se presente para su registración. Si se trata de cosas muebles no registrables o de un software, deben inscribirse en el Registro de Créditos Prendarios del lugar donde la cosa se encuentre o, en su caso, donde ésta o el software se deba poner a disposición del tomador. En el caso de inmuebles, la inscripción se mantiene por el plazo de veinte años; en los demás bienes se mantiene por diez años. En ambos casos puede renovarse antes de su vencimiento, por rogación del dador u orden judicial.", plainLanguageExplanation: "Establece el régimen de forma e inscripción. El leasing debe instrumentarse en escritura pública si tiene como objeto inmuebles, buques o aeronaves.", practicalEffects: ['En la práctica, este artículo rige forma e inscripción. El leasing debe instrumentarse en escritura pública si tiene como objeto inmuebles, buques o aeronaves.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma', 'inscripcin', 'articulo 1234'], segments: [], amendments: [] },
  { id: 'ccyc-art-1235', lawId: 'codigo-civil-comercial', number: '1235', order: 1235, title: "Modalidades de los bienes", text: "Modalidades de los bienes. A los efectos de la registración del contrato de leasing son aplicables las normas legales y reglamentarias que correspondan según la naturaleza de los bienes. En el caso de cosas muebles no registrables o software, se aplican las normas registrales de la Ley de Prenda con Registro y las demás que rigen el funcionamiento del Registro de Créditos Prendarios. Cuando el leasing comprenda a cosas muebles situadas en distintas jurisdicciones, se aplica lo dispuesto en la Ley de Prenda con Registro para iguales circunstancias. El registro debe expedir certificados e informes. El certificado que indique que sobre determinados bienes no aparece inscrito ningún contrato de leasing tiene eficacia legal hasta veinticuatro horas de expedido.", plainLanguageExplanation: "Establece el régimen de modalidades de los bienes. A los efectos de la registración del contrato de leasing son aplicables las normas legales y reglamentarias que correspondan según la naturaleza de los bienes.", practicalEffects: ['En la práctica, este artículo rige modalidades de los bienes. A los efectos de la registración del contrato de leasing son aplicables las normas legales y reglamentarias que correspondan según la naturaleza de los bienes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modalidades', 'bienes', 'articulo 1235'], segments: [], amendments: [] },
  { id: 'ccyc-art-1236', lawId: 'codigo-civil-comercial', number: '1236', order: 1236, title: "Traslado de los bienes", text: "Traslado de los bienes. El tomador no puede sustraer los bienes muebles del lugar en que deben encontrarse de acuerdo a lo estipulado en el contrato inscrito. Sólo puede trasladarlos con la conformidad expresa del dador, otorgada en el contrato o por acto escrito posterior, y después de haberse inscrito el traslado y la conformidad del dador en los registros correspondientes. Se aplican las normas pertinentes de la Ley de Prenda con Registro al respecto.", plainLanguageExplanation: "Establece el régimen de traslado de los bienes. El tomador no puede sustraer los bienes muebles del lugar en que deben encontrarse de acuerdo a lo estipulado en el contrato inscrito.", practicalEffects: ['En la práctica, este artículo rige traslado de los bienes. El tomador no puede sustraer los bienes muebles del lugar en que deben encontrarse de acuerdo a lo estipulado en el contrato inscrito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['traslado', 'bienes', 'articulo 1236'], segments: [], amendments: [] },
  { id: 'ccyc-art-1237', lawId: 'codigo-civil-comercial', number: '1237', order: 1237, title: "Oponibilidad", text: "Oponibilidad. Subrogación. El contrato debidamente inscrito es oponible a los acreedores de las partes. Los acreedores del tomador pueden subrogarse en los derechos de éste para ejercer la opción de compra.", plainLanguageExplanation: "Establece el régimen de oponibilidad. Subrogación.", practicalEffects: ['En la práctica, este artículo rige oponibilidad. Subrogación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oponibilidadarticulo 1237'], segments: [], amendments: [] },
  { id: 'ccyc-art-1238', lawId: 'codigo-civil-comercial', number: '1238', order: 1238, title: "Uso y goce del bien", text: "Uso y goce del bien. El tomador puede usar y gozar del bien objeto del leasing conforme a su destino, pero no puede venderlo, gravarlo ni disponer de él. Los gastos ordinarios y extraordinarios de conservación y uso, incluyendo seguros, impuestos y tasas, que recaigan sobre los bienes y las sanciones ocasionadas por su uso, son a cargo del tomador, excepto convención en contrario. El tomador puede arrendar el bien objeto del leasing, excepto pacto en contrario. En ningún caso el locatario o arrendatario puede pretender derechos sobre el bien que impidan o limiten en modo alguno los derechos del dador.", plainLanguageExplanation: "Establece el régimen de uso y goce del bien. El tomador puede usar y gozar del bien objeto del leasing conforme a su destino, pero no puede venderlo, gravarlo ni disponer de él.", practicalEffects: ['En la práctica, este artículo rige uso y goce del bien. El tomador puede usar y gozar del bien objeto del leasing conforme a su destino, pero no puede venderlo, gravarlo ni disponer de él.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['goce', 'bien', 'articulo 1238'], segments: [], amendments: [] },
  { id: 'ccyc-art-1239', lawId: 'codigo-civil-comercial', number: '1239', order: 1239, title: "Acción reivindicatoria", text: "Acción reivindicatoria. La venta o gravamen consentido por el tomador es inoponible al dador. El dador tiene acción reivindicatoria sobre la cosa mueble que se encuentre en poder de cualquier tercero, pudiendo hacer aplicación directa de lo dispuesto en el artículo 1249 inciso a), sin perjuicio de la responsabilidad del tomador.", plainLanguageExplanation: "Establece el régimen de acción reivindicatoria. La venta o gravamen consentido por el tomador es inoponible al dador.", practicalEffects: ['En la práctica, este artículo rige acción reivindicatoria. La venta o gravamen consentido por el tomador es inoponible al dador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'reivindicatoria', 'articulo 1239'], segments: [], amendments: [] },
  { id: 'ccyc-art-1240', lawId: 'codigo-civil-comercial', number: '1240', order: 1240, title: "Opción de compra", text: "Opción de compra. Ejercicio. La opción de compra puede ejercerse por el tomador una vez que haya pagado tres cuartas partes del canon total estipulado, o antes si así lo convinieron las partes.", plainLanguageExplanation: "Establece el régimen de opción de compra. Ejercicio.", practicalEffects: ['En la práctica, este artículo rige opción de compra. Ejercicio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['opcin', 'compra', 'articulo 1240'], segments: [], amendments: [] },
  { id: 'ccyc-art-1241', lawId: 'codigo-civil-comercial', number: '1241', order: 1241, title: "Prórroga del contrato", text: "Prórroga del contrato. El contrato puede prever su prórroga a opción del tomador y las condiciones de su ejercicio.", plainLanguageExplanation: "Establece el régimen de prórroga del contrato. El contrato puede prever su prórroga a opción del tomador y las condiciones de su ejercicio.", practicalEffects: ['En la práctica, este artículo rige prórroga del contrato. El contrato puede prever su prórroga a opción del tomador y las condiciones de su ejercicio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prrroga', 'contrato', 'articulo 1241'], segments: [], amendments: [] },
  { id: 'ccyc-art-1242', lawId: 'codigo-civil-comercial', number: '1242', order: 1242, title: "Transmisión del dominio", text: "Transmisión del dominio. El derecho del tomador a la transmisión del dominio nace con el ejercicio de la opción de compra y el pago del precio del ejercicio de la opción conforme a lo determinado en el contrato. El dominio se adquiere cumplidos esos requisitos, excepto que la ley exija otros de acuerdo con la naturaleza del bien de que se trate, a cuyo efecto las partes deben otorgar la documentación y efectuar los demás actos necesarios.", plainLanguageExplanation: "Establece el régimen de transmisión del dominio. El derecho del tomador a la transmisión del dominio nace con el ejercicio de la opción de compra y el pago del precio del ejercicio de la opción conforme a lo determinado en el contrato.", practicalEffects: ['En la práctica, este artículo rige transmisión del dominio. El derecho del tomador a la transmisión del dominio nace con el ejercicio de la opción de compra y el pago del precio del ejercicio de la opción conforme a lo determinado en el contrato.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transmisin', 'dominio', 'articulo 1242'], segments: [], amendments: [] },
  { id: 'ccyc-art-1243', lawId: 'codigo-civil-comercial', number: '1243', order: 1243, title: "Responsabilidad objetiva", text: "Responsabilidad objetiva. La responsabilidad objetiva emergente del artículo 1757 recae exclusivamente sobre el tomador o guardián de las cosas dadas en leasing.", plainLanguageExplanation: "Establece el régimen de responsabilidad objetiva. La responsabilidad objetiva emergente del artículo 1757 recae exclusivamente sobre el tomador o guardián de las cosas dadas en leasing.", practicalEffects: ['En la práctica, este artículo rige responsabilidad objetiva. La responsabilidad objetiva emergente del artículo 1757 recae exclusivamente sobre el tomador o guardián de las cosas dadas en leasing.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'objetiva', 'articulo 1243'], segments: [], amendments: [] },
  { id: 'ccyc-art-1244', lawId: 'codigo-civil-comercial', number: '1244', order: 1244, title: "Cancelación de la inscripción", text: "Cancelación de la inscripción. Supuestos. La inscripción del leasing sobre cosas muebles no registrables y software se cancela: a) por orden judicial, dictada en un proceso en el que el dador tuvo oportunidad de tomar la debida participación; b) a petición del dador o su cesionario.", plainLanguageExplanation: "Establece el régimen de cancelación de la inscripción. Supuestos.", practicalEffects: ['En la práctica, este artículo rige cancelación de la inscripción. Supuestos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cancelacin', 'inscripcin', 'articulo 1244'], segments: [], amendments: [] },
  { id: 'ccyc-art-1245', lawId: 'codigo-civil-comercial', number: '1245', order: 1245, title: "Cancelación a pedido del tomador", text: "Cancelación a pedido del tomador. El tomador puede solicitar la cancelación de la inscripción del leasing sobre cosas muebles no registrables y software si acredita: a) el cumplimiento de los recaudos previstos en el contrato inscrito para ejercer la opción de compra; b) el depósito del monto total de los cánones que restaban pagar y del precio de ejercicio de la opción, con sus accesorios, en su caso; c) la interpelación fehaciente al dador, por un plazo no inferior a quince días hábiles, ofreciéndole los pagos y solicitándole la cancelación de la inscripción; d) el cumplimiento de las demás obligaciones contractuales exigibles a su cargo.", plainLanguageExplanation: "Establece el régimen de cancelación a pedido del tomador. El tomador puede solicitar la cancelación de la inscripción del leasing sobre cosas muebles no registrables y software si acredita: a) el cumplimiento de los recaudos previstos en el contrato inscrito para ejercer la opción de compra; b) el depósito del monto total de los cánones", practicalEffects: ['En la práctica, este artículo rige cancelación a pedido del tomador. El tomador puede solicitar la cancelación de la inscripción del leasing sobre cosas muebles no registrables y software si acredita: a) el cumplimiento'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cancelacin', 'pedido', 'tomador', 'articulo 1245'], segments: [], amendments: [] },
  { id: 'ccyc-art-1246', lawId: 'codigo-civil-comercial', number: '1246', order: 1246, title: "Procedimiento de cancelación", text: "Procedimiento de cancelación. Solicitada la cancelación, el encargado del registro debe notificar al dador, en el domicilio constituido en el contrato, por carta certificada: a) si el notificado manifiesta conformidad, se cancela la inscripción; b) si el dador no formula observaciones dentro de los quince días hábiles desde la notificación, y el encargado estima que el depósito se ajusta a lo previsto en el contrato, procede a la cancelación y notifica al dador y al tomador; c) si el dador formula observaciones o el encargado estima insuficiente el depósito, lo comunica al tomador, quien tiene expeditas las acciones pertinentes.", plainLanguageExplanation: "Establece el régimen de procedimiento de cancelación. Solicitada la cancelación, el encargado del registro debe notificar al dador, en el domicilio constituido en el contrato, por carta certificada: a) si el notificado manifiesta conformidad, se cancela la inscripción; b) si el dador no formula observaciones dentro de los quince día", practicalEffects: ['En la práctica, este artículo rige procedimiento de cancelación. Solicitada la cancelación, el encargado del registro debe notificar al dador, en el domicilio constituido en el contrato, por carta certificada: a) si'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procedimiento', 'cancelacin', 'articulo 1246'], segments: [], amendments: [] },
  { id: 'ccyc-art-1247', lawId: 'codigo-civil-comercial', number: '1247', order: 1247, title: "Cesión de contratos o de créditos del dador", text: "Cesión de contratos o de créditos del dador. El dador siempre puede ceder los créditos actuales o futuros por canon o precio de ejercicio de la opción de compra. A los fines de su titulización puede hacerlo en los términos de los artículos 1614 y siguientes de este Código o en la forma prevista por la ley especial. Esta cesión no perjudica los derechos del tomador respecto del ejercicio o no ejercicio de la opción de compra o, en su caso, a la cancelación anticipada de los cánones, todo ello según lo pactado en el contrato.", plainLanguageExplanation: "Establece el régimen de cesión de contratos o de créditos del dador. El dador siempre puede ceder los créditos actuales o futuros por canon o precio de ejercicio de la opción de compra.", practicalEffects: ['En la práctica, este artículo rige cesión de contratos o de créditos del dador. El dador siempre puede ceder los créditos actuales o futuros por canon o precio de ejercicio de la opción de compra.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cesin', 'contratos', 'crditos', 'dador', 'articulo 1247'], segments: [], amendments: [] },
  { id: 'ccyc-art-1248', lawId: 'codigo-civil-comercial', number: '1248', order: 1248, title: "Incumplimiento y ejecución en caso de inmuebles", text: "Incumplimiento y ejecución en caso de inmuebles. Cuando el objeto del leasing es una cosa inmueble, el incumplimiento de la obligación del tomador de pagar el canon produce los siguientes efectos: a) si el tomador ha pagado menos de un cuarto del monto del canon total convenido, la mora es automática y el dador puede demandar judicialmente el desalojo. Se debe dar vista por cinco días al tomador, quien puede probar documentalmente el pago de los períodos que se le reclaman o paralizar el trámite, por única vez, mediante el pago de lo adeudado, con más sus intereses y costas. Caso contrario, el juez debe disponer el lanzamiento sin más trámite; b) si el tomador ha pagado un cuarto o más pero menos de tres cuartas partes del canon convenido, la mora es automática; el dador debe intimarlo al pago del o de los períodos adeudados con más sus intereses y el tomador dispone por única vez de un plazo no menor de sesenta días, contados a partir de la recepción de la notificación, para el pago del o de los períodos adeudados con más sus intereses. Pasado ese plazo sin que el pago se verifique, el dador puede demandar el desalojo, de lo que se debe dar vista por cinco días al tomador. Dentro de ese plazo, el tomador puede demostrar el pago de lo reclamado, o paralizar el procedimiento mediante el pago de lo adeudado con más sus intereses y costas, si antes no hubiese recurrido a este procedimiento. Si, según el contrato, el tomador puede hacer ejercicio de la opción de compra, en el mismo plazo puede pagar, además, el precio de ejercicio de esa opción, con sus accesorios contractuales y legales. En caso contrario, el juez debe disponer el lanzamiento sin más trámite; c) Si el incumplimiento se produce después de haber pagado las tres cuartas partes del canon, la mora es automática; el dador debe intimarlo al pago y el tomador tiene la opción de pagar lo adeudado más sus intereses dentro de los noventa días, contados a partir de la recepción de la notificación si antes no hubiera recurrido a ese procedimiento, o el precio de ejercicio de la opción de compra que resulte de la aplicación del contrato, a la fecha de la mora, con sus intereses. Pasado ese plazo sin que el pago se verifique, el dador puede demandar el desalojo, de lo que debe darse vista al tomador por cinco días, quien sólo puede paralizarlo ejerciendo alguna de las opciones previstas en este inciso, agregándole las costas del proceso; d) producido el desalojo, el dador puede reclamar el pago de los períodos de canon adeudados hasta el momento del lanzamiento, con más sus intereses y costas, por la vía ejecutiva. El dador puede también reclamar los daños y perjuicios que resulten del deterioro anormal de la cosa imputable al tomador por dolo, culpa o negligencia por la vía procesal pertinente.", plainLanguageExplanation: "Establece el régimen de incumplimiento y ejecución en caso de inmuebles. Cuando el objeto del leasing es una cosa inmueble, el incumplimiento de la obligación del tomador de pagar el canon produce los siguientes efectos: a) si el tomador ha pagado menos de un cuarto del monto del canon total convenido, la mora es automática y el dador puede demandar j", practicalEffects: ['En la práctica, este artículo rige incumplimiento y ejecución en caso de inmuebles. Cuando el objeto del leasing es una cosa inmueble, el incumplimiento de la obligación del tomador de pagar el canon produce los siguientes efectos: a)'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incumplimiento', 'ejecucin', 'caso', 'inmuebles', 'articulo 1248'], segments: [], amendments: [] },
  { id: 'ccyc-art-1249', lawId: 'codigo-civil-comercial', number: '1249', order: 1249, title: "Secuestro y ejecución en caso de muebles", text: "Secuestro y ejecución en caso de muebles. Cuando el objeto de leasing es una cosa mueble, ante la mora del tomador en el pago del canon, el dador puede: a) obtener el inmediato secuestro del bien, con la sola presentación del contrato inscrito, y la prueba de haber interpelado al tomador por un plazo no menor de cinco días para la regularización. Producido el secuestro, queda resuelto el contrato. El dador puede promover ejecución por el cobro del canon que se haya devengado ordinariamente hasta el período íntegro en que se produjo el secuestro, la cláusula penal pactada en el contrato y sus intereses; todo ello sin perjuicio de la acción del dador por los daños y perjuicios, y la acción del tomador si correspondieran; o b) accionar por vía ejecutiva por el cobro del canon no pagado, incluyendo la totalidad del canon pendiente; si así se hubiera convenido, con la sola presentación del contrato inscripto y sus accesorios. En este caso, sólo procede el secuestro cuando ha vencido el plazo ordinario del leasing sin haberse pagado el canon íntegro y el precio de la opción de compra, o cuando se demuestre sumariamente el peligro en la conservación del bien, debiendo el dador otorgar caución suficiente. En el juicio ejecutivo previsto en ambos incisos, puede incluirse la ejecución contra los fiadores o garantes del tomador. El domicilio constituido es el fijado en el contrato.", plainLanguageExplanation: "Establece el régimen de secuestro y ejecución en caso de muebles. Cuando el objeto de leasing es una cosa mueble, ante la mora del tomador en el pago del canon, el dador puede: a) obtener el inmediato secuestro del bien, con la sola presentación del contrato inscrito, y la prueba de haber interpelado al tomador por un plazo no menor de cinco dí", practicalEffects: ['En la práctica, este artículo rige secuestro y ejecución en caso de muebles. Cuando el objeto de leasing es una cosa mueble, ante la mora del tomador en el pago del canon, el dador puede: a) obtener el inmediato secuestro del b'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['secuestro', 'ejecucin', 'caso', 'muebles', 'articulo 1249'], segments: [], amendments: [] },
  { id: 'ccyc-art-1250', lawId: 'codigo-civil-comercial', number: '1250', order: 1250, title: "Normas supletorias", text: "Normas supletorias. En todo lo no previsto por el presente Capítulo, al contrato de leasing se le aplican subsidiariamente las reglas del contrato de locación, en cuanto sean compatibles, mientras el tomador no ha pagado la totalidad del canon y ejercido la opción, con pago de su precio. No son aplicables al leasing las disposiciones relativas a plazos mínimos y máximos de la locación de cosas ni las excluidas convencionalmente. Se le aplican subsidiariamente las normas del contrato de compraventa para la determinación del precio de ejercicio de la opción de compra y para los actos posteriores a su ejercicio y pago. CAPITULO 6 Obra y servicios SECCION 1ª Disposiciones comunes a las obras y a los servicios", plainLanguageExplanation: "Establece el régimen de normas supletorias. En todo lo no previsto por el presente Capítulo, al contrato de leasing se le aplican subsidiariamente las reglas del contrato de locación, en cuanto sean compatibles, mientras el tomador no ha pagado la totalidad del canon y ejercido la opción, con pago de su precio.", practicalEffects: ['En la práctica, este artículo rige normas supletorias. En todo lo no previsto por el presente Capítulo, al contrato de leasing se le aplican subsidiariamente las reglas del contrato de locación, en cuanto'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'supletorias', 'articulo 1250'], segments: [], amendments: [] },
  { id: 'ccyc-art-1251', lawId: 'codigo-civil-comercial', number: '1251', order: 1251, title: "Definición", text: "Definición. Hay contrato de obra o de servicios cuando una persona, según el caso el contratista o el prestador de servicios, actuando independientemente, se obliga a favor de otra, llamada comitente, a realizar una obra material o intelectual o a proveer un servicio mediante una retribución. El contrato es gratuito si las partes así lo pactan o cuando por las circunstancias del caso puede presumirse la intención de beneficiar.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de obra o de servicios cuando una persona, según el caso el contratista o el prestador de servicios, actuando independientemente, se obliga a favor de otra, llamada comitente, a realizar una obra material o intelectual o a proveer un servicio mediante una retribución.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de obra o de servicios cuando una persona, según el caso el contratista o el prestador de servicios, actuando independientemente, se obli'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1251'], segments: [], amendments: [] },
  { id: 'ccyc-art-1252', lawId: 'codigo-civil-comercial', number: '1252', order: 1252, title: "Calificación del contrato", text: "Calificación del contrato. Si hay duda sobre la calificación del contrato, se entiende que hay contrato de servicios cuando la obligación de hacer consiste en realizar cierta actividad independiente de su eficacia. Se considera que el contrato es de obra cuando se promete un resultado eficaz, reproducible o susceptible de entrega. Los servicios prestados en relación de dependencia se rigen por las normas del derecho laboral. Las disposiciones de este Capítulo se integran con las reglas específicas que resulten aplicables a servicios u obras especialmente regulados.", plainLanguageExplanation: "Establece el régimen de calificación del contrato. Si hay duda sobre la calificación del contrato, se entiende que hay contrato de servicios cuando la obligación de hacer consiste en realizar cierta actividad independiente de su eficacia.", practicalEffects: ['En la práctica, este artículo rige calificación del contrato. Si hay duda sobre la calificación del contrato, se entiende que hay contrato de servicios cuando la obligación de hacer consiste en realizar cierta actividad independiente de su eficacia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['calificacin', 'contrato', 'articulo 1252'], segments: [], amendments: [] },
  { id: 'ccyc-art-1253', lawId: 'codigo-civil-comercial', number: '1253', order: 1253, title: "Medios utilizados", text: "Medios utilizados. A falta de ajuste sobre el modo de hacer la obra, el contratista o prestador de los servicios elige libremente los medios de ejecución del contrato.", plainLanguageExplanation: "Establece el régimen de medios utilizados. A falta de ajuste sobre el modo de hacer la obra, el contratista o prestador de los servicios elige libremente los medios de ejecución del contrato.", practicalEffects: ['En la práctica, este artículo rige medios utilizados. A falta de ajuste sobre el modo de hacer la obra, el contratista o prestador de los servicios elige libremente los medios de ejecución del contrato.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medios', 'utilizados', 'articulo 1253'], segments: [], amendments: [] },
  { id: 'ccyc-art-1254', lawId: 'codigo-civil-comercial', number: '1254', order: 1254, title: "Cooperación de terceros", text: "Cooperación de terceros. El contratista o prestador de servicios puede valerse de terceros para ejecutar el servicio, excepto que de lo estipulado o de la índole de la obligación resulte que fue elegido por sus cualidades para realizarlo personalmente en todo o en parte. En cualquier caso, conserva la dirección y la responsabilidad de la ejecución.", plainLanguageExplanation: "Establece el régimen de cooperación de terceros. El contratista o prestador de servicios puede valerse de terceros para ejecutar el servicio, excepto que de lo estipulado o de la índole de la obligación resulte que fue elegido por sus cualidades para realizarlo personalmente en todo o en parte.", practicalEffects: ['En la práctica, este artículo rige cooperación de terceros. El contratista o prestador de servicios puede valerse de terceros para ejecutar el servicio, excepto que de lo estipulado o de la índole de la obligac'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cooperacin', 'terceros', 'articulo 1254'], segments: [], amendments: [] },
  { id: 'ccyc-art-1255', lawId: 'codigo-civil-comercial', number: '1255', order: 1255, title: "Precio", text: "Precio. El precio se determina por el contrato, la ley, los usos o, en su defecto, por decisión judicial. Las leyes arancelarias no pueden cercenar la facultad de las partes de determinar el precio de las obras o de los servicios. Cuando dicho precio debe ser establecido judicialmente sobre la base de la aplicación de dichas leyes, su determinación debe adecuarse a la labor cumplida por el prestador. Si la aplicación estricta de los aranceles locales conduce a una evidente e injustificada desproporción entre la retribución resultante y la importancia de la labor cumplida, el juez puede fijar equitativamente la retribución. Si la obra o el servicio se ha contratado por un precio global o por una unidad de medida, ninguna de las partes puede pretender la modificación del precio total o de la unidad de medida, respectivamente, con fundamento en que la obra, el servicio o la unidad exige menos o más trabajo o que su costo es menor o mayor al previsto, excepto lo dispuesto en el artículo 1091.", plainLanguageExplanation: "Establece el régimen de precio. El precio se determina por el contrato, la ley, los usos o, en su defecto, por decisión judicial.", practicalEffects: ['En la práctica, este artículo rige precio. El precio se determina por el contrato, la ley, los usos o, en su defecto, por decisión judicial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['precioarticulo 1255'], segments: [], amendments: [] },
  { id: 'ccyc-art-1256', lawId: 'codigo-civil-comercial', number: '1256', order: 1256, title: "Obligaciones del contratista y del prestador", text: "Obligaciones del contratista y del prestador. El contratista o prestador de servicios está obligado a: a) ejecutar el contrato conforme a las previsiones contractuales y a los conocimientos razonablemente requeridos al tiempo de su realización por el arte, la ciencia y la técnica correspondientes a la actividad desarrollada; b) informar al comitente sobre los aspectos esenciales del cumplimiento de la obligación comprometida; c) proveer los materiales adecuados que son necesarios para la ejecución de la obra o del servicio, excepto que algo distinto se haya pactado o resulte de los usos; d) usar diligentemente los materiales provistos por el comitente e informarle inmediatamente en caso de que esos materiales sean impropios o tengan vicios que el contratista o prestador debiese conocer; e) ejecutar la obra o el servicio en el tiempo convenido o, en su defecto, en el que razonablemente corresponda según su índole.", plainLanguageExplanation: "Establece el régimen de obligaciones del contratista y del prestador. El contratista o prestador de servicios está obligado a: a) ejecutar el contrato conforme a las previsiones contractuales y a los conocimientos razonablemente requeridos al tiempo de su realización por el arte, la ciencia y la técnica correspondientes a la actividad desarrollada;", practicalEffects: ['En la práctica, este artículo rige obligaciones del contratista y del prestador. El contratista o prestador de servicios está obligado a: a) ejecutar el contrato conforme a las previsiones contractuales y a los conocimientos razona'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'contratista', 'prestador', 'articulo 1256'], segments: [], amendments: [] },
  { id: 'ccyc-art-1257', lawId: 'codigo-civil-comercial', number: '1257', order: 1257, title: "Obligaciones del comitente", text: "Obligaciones del comitente. El comitente está obligado a: a) pagar la retribución; b) proporcionar al contratista o al prestador la colaboración necesaria, conforme a las características de la obra o del servicio; c) recibir la obra si fue ejecutada conforme a lo dispuesto en el artículo 1256.", plainLanguageExplanation: "Establece el régimen de obligaciones del comitente. El comitente está obligado a: a) pagar la retribución; b) proporcionar al contratista o al prestador la colaboración necesaria, conforme a las características de la obra o del servicio; c) recibir la obra si fue ejecutada conforme a lo dispuesto en el artículo 1256.", practicalEffects: ['En la práctica, este artículo rige obligaciones del comitente. El comitente está obligado a: a) pagar la retribución; b) proporcionar al contratista o al prestador la colaboración necesaria, conforme a las caracte'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'comitente', 'articulo 1257'], segments: [], amendments: [] },
  { id: 'ccyc-art-1258', lawId: 'codigo-civil-comercial', number: '1258', order: 1258, title: "Riesgos de la contratación", text: "Riesgos de la contratación. Si los bienes necesarios para la ejecución de la obra o del servicio perecen por fuerza mayor, la pérdida la soporta la parte que debía proveerlos.", plainLanguageExplanation: "Establece el régimen de riesgos de la contratación. Si los bienes necesarios para la ejecución de la obra o del servicio perecen por fuerza mayor, la pérdida la soporta la parte que debía proveerlos.", practicalEffects: ['En la práctica, este artículo rige riesgos de la contratación. Si los bienes necesarios para la ejecución de la obra o del servicio perecen por fuerza mayor, la pérdida la soporta la parte que debía proveerlos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['riesgos', 'contratacin', 'articulo 1258'], segments: [], amendments: [] },
  { id: 'ccyc-art-1259', lawId: 'codigo-civil-comercial', number: '1259', order: 1259, title: "Muerte del comitente", text: "Muerte del comitente. La muerte del comitente no extingue el contrato, excepto que haga imposible o inútil la ejecución.", plainLanguageExplanation: "Establece el régimen de muerte del comitente. La muerte del comitente no extingue el contrato, excepto que haga imposible o inútil la ejecución.", practicalEffects: ['En la práctica, este artículo rige muerte del comitente. La muerte del comitente no extingue el contrato, excepto que haga imposible o inútil la ejecución.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['muerte', 'comitente', 'articulo 1259'], segments: [], amendments: [] },
  { id: 'ccyc-art-1260', lawId: 'codigo-civil-comercial', number: '1260', order: 1260, title: "Muerte del contratista o prestador", text: "Muerte del contratista o prestador. La muerte del contratista o prestador extingue el contrato, excepto que el comitente acuerde continuarlo con los herederos de aquél. En caso de extinción, el comitente debe pagar el costo de los materiales aprovechables y el valor de la parte realizada en proporción al precio total convenido.", plainLanguageExplanation: "Establece el régimen de muerte del contratista o prestador. La muerte del contratista o prestador extingue el contrato, excepto que el comitente acuerde continuarlo con los herederos de aquél.", practicalEffects: ['En la práctica, este artículo rige muerte del contratista o prestador. La muerte del contratista o prestador extingue el contrato, excepto que el comitente acuerde continuarlo con los herederos de aquél.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['muerte', 'contratista', 'prestador', 'articulo 1260'], segments: [], amendments: [] },
  { id: 'ccyc-art-1261', lawId: 'codigo-civil-comercial', number: '1261', order: 1261, title: "Desistimiento unilateral", text: "Desistimiento unilateral. El comitente puede desistir del contrato por su sola voluntad, aunque la ejecución haya comenzado; pero debe indemnizar al prestador todos los gastos y trabajos realizados y la utilidad que hubiera podido obtener. El juez puede reducir equitativamente la utilidad si la aplicación estricta de la norma conduce a una notoria injusticia. SECCION 2ª Disposiciones especiales para las obras", plainLanguageExplanation: "Establece el régimen de desistimiento unilateral. El comitente puede desistir del contrato por su sola voluntad, aunque la ejecución haya comenzado; pero debe indemnizar al prestador todos los gastos y trabajos realizados y la utilidad que hubiera podido obtener.", practicalEffects: ['En la práctica, este artículo rige desistimiento unilateral. El comitente puede desistir del contrato por su sola voluntad, aunque la ejecución haya comenzado; pero debe indemnizar al prestador todos los gastos'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desistimiento', 'unilateral', 'articulo 1261'], segments: [], amendments: [] },
  { id: 'ccyc-art-1262', lawId: 'codigo-civil-comercial', number: '1262', order: 1262, title: "Sistemas de contratación", text: "Sistemas de contratación. La obra puede ser contratada por ajuste alzado, también denominado 'retribución global', por unidad de medida, por coste y costas o por cualquier otro sistema convenido por las partes. La contratación puede hacerse con o sin provisión de materiales por el comitente. Si se trata de inmuebles, la obra puede realizarse en terreno del comitente o de un tercero. Si nada se convino ni surge de los usos, se presume, excepto prueba en contrario, que la obra fue contratada por ajuste alzado y que es el contratista quien provee los materiales.", plainLanguageExplanation: "Establece el régimen de sistemas de contratación. La obra puede ser contratada por ajuste alzado, también denominado 'retribución global', por unidad de medida, por coste y costas o por cualquier otro sistema convenido por las partes.", practicalEffects: ['En la práctica, este artículo rige sistemas de contratación. La obra puede ser contratada por ajuste alzado, también denominado \'retribución global\', por unidad de medida, por coste y costas o por cualquier otro sistema convenido por las partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sistemas', 'contratacin', 'articulo 1262'], segments: [], amendments: [] },
  { id: 'ccyc-art-1263', lawId: 'codigo-civil-comercial', number: '1263', order: 1263, title: "Retribución", text: "Retribución. Si la obra se contrata por el sistema de ejecución a coste y costas, la retribución se determina sobre el valor de los materiales, de la mano de obra y de otros gastos directos o indirectos.", plainLanguageExplanation: "Establece el régimen de retribución. Si la obra se contrata por el sistema de ejecución a coste y costas, la retribución se determina sobre el valor de los materiales, de la mano de obra y de otros gastos directos o indirectos.", practicalEffects: ['En la práctica, este artículo rige retribución. Si la obra se contrata por el sistema de ejecución a coste y costas, la retribución se determina sobre el valor de los materiales, de la mano de obra'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retribucinarticulo 1263'], segments: [], amendments: [] },
  { id: 'ccyc-art-1264', lawId: 'codigo-civil-comercial', number: '1264', order: 1264, title: "Variaciones del proyecto convenido", text: "Variaciones del proyecto convenido. Cualquiera sea el sistema de contratación, el contratista no puede variar el proyecto ya aceptado sin autorización escrita del comitente, excepto que las modificaciones sean necesarias para ejecutar la obra conforme a las reglas del arte y no hubiesen podido ser previstas al momento de la contratación; la necesidad de tales modificaciones debe ser comunicada inmediatamente al comitente con indicación de su costo estimado. Si las variaciones implican un aumento superior a la quinta parte del precio pactado, el comitente puede extinguirlo comunicando su decisión dentro del plazo de diez días de haber conocido la necesidad de la modificación y su costo estimado. El comitente puede introducir variantes al proyecto siempre que no impliquen cambiar sustancialmente la naturaleza de la obra.", plainLanguageExplanation: "Establece el régimen de variaciones del proyecto convenido. Cualquiera sea el sistema de contratación, el contratista no puede variar el proyecto ya aceptado sin autorización escrita del comitente, excepto que las modificaciones sean necesarias para ejecutar la obra conforme a las reglas del arte y no hubiesen podido ser previstas al mome", practicalEffects: ['En la práctica, este artículo rige variaciones del proyecto convenido. Cualquiera sea el sistema de contratación, el contratista no puede variar el proyecto ya aceptado sin autorización escrita del comitente, excepto que'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['variaciones', 'proyecto', 'convenido', 'articulo 1264'], segments: [], amendments: [] },
  { id: 'ccyc-art-1265', lawId: 'codigo-civil-comercial', number: '1265', order: 1265, title: "Diferencias de retribución surgidas de modificaciones autorizadas", text: "Diferencias de retribución surgidas de modificaciones autorizadas. A falta de acuerdo, las diferencias de precio surgidas de las modificaciones autorizadas en este Capítulo se fijan judicialmente.", plainLanguageExplanation: "Establece el régimen de diferencias de retribución surgidas de modificaciones autorizadas. A falta de acuerdo, las diferencias de precio surgidas de las modificaciones autorizadas en este Capítulo se fijan judicialmente.", practicalEffects: ['En la práctica, este artículo rige diferencias de retribución surgidas de modificaciones autorizadas. A falta de acuerdo, las diferencias de precio surgidas de las modificaciones autorizadas en este Capítulo se fijan judicialmente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['diferencias', 'retribucin', 'surgidas', 'modificaciones', 'autorizadas', 'articulo 1265'], segments: [], amendments: [] },
  { id: 'ccyc-art-1266', lawId: 'codigo-civil-comercial', number: '1266', order: 1266, title: "Obra por pieza o medida", text: "Obra por pieza o medida. Si la obra fue pactada por pieza o medida sin designación del número de piezas o de la medida total, el contrato puede ser extinguido por cualquiera de los contratantes concluidas que sean las partes designadas como límite mínimo, debiéndose las prestaciones correspondientes a la parte concluida. Si se ha designado el número de piezas o la medida total, el contratista está obligado a entregar la obra concluida y el comitente a pagar la retribución que resulte del total de las unidades pactadas.", plainLanguageExplanation: "Establece el régimen de obra por pieza o medida. Si la obra fue pactada por pieza o medida sin designación del número de piezas o de la medida total, el contrato puede ser extinguido por cualquiera de los contratantes concluidas que sean las partes designadas como límite mínimo, debiéndose las prestaciones correspondientes a la parte concluida.", practicalEffects: ['En la práctica, este artículo rige obra por pieza o medida. Si la obra fue pactada por pieza o medida sin designación del número de piezas o de la medida total, el contrato puede ser extinguido por cualquiera d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obra', 'pieza', 'medida', 'articulo 1266'], segments: [], amendments: [] },
  { id: 'ccyc-art-1267', lawId: 'codigo-civil-comercial', number: '1267', order: 1267, title: "Imposibilidad de ejecución de la prestación sin culpa", text: "Imposibilidad de ejecución de la prestación sin culpa. Si la ejecución de una obra o su continuación se hace imposible por causa no imputable a ninguna de las partes, el contrato se extingue. El contratista tiene derecho a obtener una compensación equitativa por la tarea efectuada.", plainLanguageExplanation: "Establece el régimen de imposibilidad de ejecución de la prestación sin culpa. Si la ejecución de una obra o su continuación se hace imposible por causa no imputable a ninguna de las partes, el contrato se extingue.", practicalEffects: ['En la práctica, este artículo rige imposibilidad de ejecución de la prestación sin culpa. Si la ejecución de una obra o su continuación se hace imposible por causa no imputable a ninguna de las partes, el contrato se extingue.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imposibilidad', 'ejecucin', 'prestacin', 'culpa', 'articulo 1267'], segments: [], amendments: [] },
  { id: 'ccyc-art-1268', lawId: 'codigo-civil-comercial', number: '1268', order: 1268, title: "Destrucción o deterioro de la obra por caso fortuito antes de la entrega", text: "Destrucción o deterioro de la obra por caso fortuito antes de la entrega. La destrucción o el deterioro de una parte importante de la obra por caso fortuito antes de haber sido recibida autoriza a cualquiera de las partes a dar por extinguido el contrato, con los siguientes efectos: a) si el contratista provee los materiales y la obra se realiza en inmueble del comitente, el contratista tiene derecho a su valor y a una compensación equitativa por la tarea efectuada; b) si la causa de la destrucción o del deterioro importante es la mala calidad o inadecuación de los materiales, no se debe la remuneración pactada aunque el contratista haya advertido oportunamente esa circunstancia al comitente; c) si el comitente está en mora en la recepción al momento de la destrucción o del deterioro de parte importante de la obra, debe la remuneración pactada.", plainLanguageExplanation: "Establece el régimen de destrucción o deterioro de la obra por caso fortuito antes de la entrega. La destrucción o el deterioro de una parte importante de la obra por caso fortuito antes de haber sido recibida autoriza a cualquiera de las partes a dar por extinguido el contrato, con los siguientes efectos: a) si el contratista provee los materiales y la obra se realiza en inm", practicalEffects: ['En la práctica, este artículo rige destrucción o deterioro de la obra por caso fortuito antes de la entrega. La destrucción o el deterioro de una parte importante de la obra por caso fortuito antes de haber sido recibida autoriza a cualquiera de las partes a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['destruccin', 'deterioro', 'obra', 'caso', 'fortuito', 'antes', 'entrega', 'articulo 1268'], segments: [], amendments: [] },
  { id: 'ccyc-art-1269', lawId: 'codigo-civil-comercial', number: '1269', order: 1269, title: "Derecho a verificar", text: "Derecho a verificar. En todo momento, y siempre que no perjudique el desarrollo de los trabajos, el comitente de una obra tiene derecho a verificar a su costa el estado de avance, la calidad de los materiales utilizados y los trabajos efectuados.", plainLanguageExplanation: "Establece el régimen de derecho a verificar. En todo momento, y siempre que no perjudique el desarrollo de los trabajos, el comitente de una obra tiene derecho a verificar a su costa el estado de avance, la calidad de los materiales utilizados y los trabajos efectuados.", practicalEffects: ['En la práctica, este artículo rige derecho a verificar. En todo momento, y siempre que no perjudique el desarrollo de los trabajos, el comitente de una obra tiene derecho a verificar a su costa el estado de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'verificar', 'articulo 1269'], segments: [], amendments: [] },
  { id: 'ccyc-art-1270', lawId: 'codigo-civil-comercial', number: '1270', order: 1270, title: "Aceptación de la obra", text: "Aceptación de la obra. La obra se considera aceptada cuando concurren las circunstancias del artículo 747.", plainLanguageExplanation: "Establece el régimen de aceptación de la obra. La obra se considera aceptada cuando concurren las circunstancias del artículo 747.", practicalEffects: ['En la práctica, este artículo rige aceptación de la obra. La obra se considera aceptada cuando concurren las circunstancias del artículo 747.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aceptacin', 'obra', 'articulo 1270'], segments: [], amendments: [] },
  { id: 'ccyc-art-1271', lawId: 'codigo-civil-comercial', number: '1271', order: 1271, title: "Vicios o defectos y diferencias en la calidad", text: "Vicios o defectos y diferencias en la calidad. Las normas sobre vicios o defectos se aplican a las diferencias en la calidad de la obra.", plainLanguageExplanation: "Establece el régimen de vicios o defectos y diferencias en la calidad. Las normas sobre vicios o defectos se aplican a las diferencias en la calidad de la obra.", practicalEffects: ['En la práctica, este artículo rige vicios o defectos y diferencias en la calidad. Las normas sobre vicios o defectos se aplican a las diferencias en la calidad de la obra.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['vicios', 'defectos', 'diferencias', 'calidad', 'articulo 1271'], segments: [], amendments: [] },
  { id: 'ccyc-art-1272', lawId: 'codigo-civil-comercial', number: '1272', order: 1272, title: "Plazos de garantía", text: "Plazos de garantía. Si se conviene o es de uso un plazo de garantía para que el comitente verifique la obra o compruebe su funcionamiento, la recepción se considera provisional y no hace presumir la aceptación. Si se trata de vicios que no afectan la solidez ni hacen la obra impropia para su destino, no se pactó un plazo de garantía ni es de uso otorgarlo, aceptada la obra, el contratista: a) queda libre de responsabilidad por los vicios aparentes; b) responde de los vicios o defectos no ostensibles al momento de la recepción, con la extensión y en los plazos previstos para la garantía por vicios ocultos prevista en los artículos 1054 y concordantes.", plainLanguageExplanation: "Establece el régimen de plazos de garantía. Si se conviene o es de uso un plazo de garantía para que el comitente verifique la obra o compruebe su funcionamiento, la recepción se considera provisional y no hace presumir la aceptación.", practicalEffects: ['En la práctica, este artículo rige plazos de garantía. Si se conviene o es de uso un plazo de garantía para que el comitente verifique la obra o compruebe su funcionamiento, la recepción se considera provisional y no hace presumir la aceptación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazos', 'garanta', 'articulo 1272'], segments: [], amendments: [] },
  { id: 'ccyc-art-1273', lawId: 'codigo-civil-comercial', number: '1273', order: 1273, title: "Obra en ruina o impropia para su destino", text: "Obra en ruina o impropia para su destino. El constructor de una obra realizada en inmueble destinada por su naturaleza a tener larga duración responde al comitente y al adquirente de la obra por los daños que comprometen su solidez y por los que la hacen impropia para su destino. El constructor sólo se libera si prueba la incidencia de una causa ajena. No es causa ajena el vicio del suelo, aunque el terreno pertenezca al comitente o a un tercero, ni el vicio de los materiales, aunque no sean provistos por el contratista.", plainLanguageExplanation: "Establece el régimen de obra en ruina o impropia para su destino. El constructor de una obra realizada en inmueble destinada por su naturaleza a tener larga duración responde al comitente y al adquirente de la obra por los daños que comprometen su solidez y por los que la hacen impropia para su destino.", practicalEffects: ['En la práctica, este artículo rige obra en ruina o impropia para su destino. El constructor de una obra realizada en inmueble destinada por su naturaleza a tener larga duración responde al comitente y al adquirente de la obra p'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obra', 'ruina', 'impropia', 'para', 'destino', 'articulo 1273'], segments: [], amendments: [] },
  { id: 'ccyc-art-1274', lawId: 'codigo-civil-comercial', number: '1274', order: 1274, title: "Extensión de la responsabilidad por obra en ruina o impropia para su destino", text: "Extensión de la responsabilidad por obra en ruina o impropia para su destino. La responsabilidad prevista en el artículo 1273 se extiende concurrentemente: a) a toda persona que vende una obra que ella ha construido o ha hecho construir si hace de esa actividad su profesión habitual; b) a toda persona que, aunque actuando en calidad de mandatario del dueño de la obra, cumple una misión semejante a la de un contratista; c) según la causa del daño, al subcontratista, al proyectista, al director de la obra y a cualquier otro profesional ligado al comitente por un contrato de obra de construcción referido a la obra dañada o a cualquiera de sus partes.", plainLanguageExplanation: "Establece el régimen de extensión de la responsabilidad por obra en ruina o impropia para su destino. La responsabilidad prevista en el artículo 1273 se extiende concurrentemente: a) a toda persona que vende una obra que ella ha construido o ha hecho construir si hace de esa actividad su profesión habitual; b) a toda persona que, aunque actuando en calidad de mandatario del dueño", practicalEffects: ['En la práctica, este artículo rige extensión de la responsabilidad por obra en ruina o impropia para su destino. La responsabilidad prevista en el artículo 1273 se extiende concurrentemente: a) a toda persona que vende una obra que ella ha construido o ha hecho c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extensin', 'responsabilidad', 'obra', 'ruina', 'impropia', 'para', 'destino', 'articulo 1274'], segments: [], amendments: [] },
  { id: 'ccyc-art-1275', lawId: 'codigo-civil-comercial', number: '1275', order: 1275, title: "Plazo de caducidad", text: "Plazo de caducidad. Para que sea aplicable la responsabilidad prevista en los artículos 1273 y 1274, el daño debe producirse dentro de los diez años de aceptada la obra.", plainLanguageExplanation: "Establece el régimen de plazo de caducidad. Para que sea aplicable la responsabilidad prevista en los artículos 1273 y 1274, el daño debe producirse dentro de los diez años de aceptada la obra.", practicalEffects: ['En la práctica, este artículo rige plazo de caducidad. Para que sea aplicable la responsabilidad prevista en los artículos 1273 y 1274, el daño debe producirse dentro de los diez años de aceptada la obra.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazo', 'caducidad', 'articulo 1275'], segments: [], amendments: [] },
  { id: 'ccyc-art-1276', lawId: 'codigo-civil-comercial', number: '1276', order: 1276, title: "Nulidad de la cláusula de exclusión o limitación de la responsabilidad", text: "Nulidad de la cláusula de exclusión o limitación de la responsabilidad. Toda cláusula que dispensa o limita la responsabilidad prevista para los daños que comprometen la solidez de una obra realizada en inmueble destinada a larga duración o que la hacen impropia para su destino, se tiene por no escrita.", plainLanguageExplanation: "Establece el régimen de nulidad de la cláusula de exclusión o limitación de la responsabilidad. Toda cláusula que dispensa o limita la responsabilidad prevista para los daños que comprometen la solidez de una obra realizada en inmueble destinada a larga duración o que la hacen impropia para su destino, se tiene por no escrita.", practicalEffects: ['En la práctica, este artículo rige nulidad de la cláusula de exclusión o limitación de la responsabilidad. Toda cláusula que dispensa o limita la responsabilidad prevista para los daños que comprometen la solidez de una obra realizada en inmueble destinada'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidad', 'clusula', 'exclusin', 'limitacin', 'responsabilidad', 'articulo 1276'], segments: [], amendments: [] },
  { id: 'ccyc-art-1277', lawId: 'codigo-civil-comercial', number: '1277', order: 1277, title: "Responsabilidades complementarias", text: "Responsabilidades complementarias. El constructor, los subcontratistas y los profesionales que intervienen en una construcción están obligados a observar las normas administrativas y son responsables, incluso frente a terceros, de cualquier daño producido por el incumplimiento de tales disposiciones. SECCION 3ª Normas especiales para los servicios", plainLanguageExplanation: "Establece el régimen de responsabilidades complementarias. El constructor, los subcontratistas y los profesionales que intervienen en una construcción están obligados a observar las normas administrativas y son responsables, incluso frente a terceros, de cualquier daño producido por el incumplimiento de tales disposiciones.", practicalEffects: ['En la práctica, este artículo rige responsabilidades complementarias. El constructor, los subcontratistas y los profesionales que intervienen en una construcción están obligados a observar las normas administrativas y so'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidades', 'complementarias', 'articulo 1277'], segments: [], amendments: [] },
  { id: 'ccyc-art-1278', lawId: 'codigo-civil-comercial', number: '1278', order: 1278, title: "Normas aplicables", text: "Normas aplicables. Resultan aplicables a los servicios las normas de la Sección 1ª de este Capítulo y las correspondientes a las obligaciones de hacer.", plainLanguageExplanation: "Establece el régimen de normas aplicables. Resultan aplicables a los servicios las normas de la Sección 1ª de este Capítulo y las correspondientes a las obligaciones de hacer.", practicalEffects: ['En la práctica, este artículo rige normas aplicables. Resultan aplicables a los servicios las normas de la Sección 1ª de este Capítulo y las correspondientes a las obligaciones de hacer.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'aplicables', 'articulo 1278'], segments: [], amendments: [] },
  { id: 'ccyc-art-1279', lawId: 'codigo-civil-comercial', number: '1279', order: 1279, title: "Servicios continuados", text: "Servicios continuados. El contrato de servicios continuados puede pactarse por tiempo determinado. Si nada se ha estipulado, se entiende que lo ha sido por tiempo indeterminado. Cualquiera de las partes puede poner fin al contrato de duración indeterminada; para ello debe dar preaviso con razonable anticipación. CAPITULO 7 Transporte SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de servicios continuados. El contrato de servicios continuados puede pactarse por tiempo determinado.", practicalEffects: ['En la práctica, este artículo rige servicios continuados. El contrato de servicios continuados puede pactarse por tiempo determinado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['servicios', 'continuados', 'articulo 1279'], segments: [], amendments: [] },
  { id: 'ccyc-art-1280', lawId: 'codigo-civil-comercial', number: '1280', order: 1280, title: "Definición", text: "Definición. Hay contrato de transporte cuando una parte llamada transportista o porteador se obliga a trasladar personas o cosas de un lugar a otro, y la otra, llamada pasajero o cargador, se obliga a pagar un precio o flete.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de transporte cuando una parte llamada transportista o porteador se obliga a trasladar personas o cosas de un lugar a otro, y la otra, llamada pasajero o cargador, se obliga a pagar un precio o flete.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de transporte cuando una parte llamada transportista o porteador se obliga a trasladar personas o cosas de un lugar a otro, y la otra, ll'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1280'], segments: [], amendments: [] },
  { id: 'ccyc-art-1281', lawId: 'codigo-civil-comercial', number: '1281', order: 1281, title: "Ambito de aplicación", text: "Ambito de aplicación. Excepto lo dispuesto en leyes especiales, las reglas de este Capítulo se aplican cualquiera que sea el medio empleado para el transporte. El transporte multimodal se rige por la ley especial.", plainLanguageExplanation: "Establece el régimen de ambito de aplicación. Excepto lo dispuesto en leyes especiales, las reglas de este Capítulo se aplican cualquiera que sea el medio empleado para el transporte.", practicalEffects: ['En la práctica, este artículo rige ambito de aplicación. Excepto lo dispuesto en leyes especiales, las reglas de este Capítulo se aplican cualquiera que sea el medio empleado para el transporte.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ambito', 'aplicacin', 'articulo 1281'], segments: [], amendments: [] },
  { id: 'ccyc-art-1282', lawId: 'codigo-civil-comercial', number: '1282', order: 1282, title: "Transporte gratuito", text: "Transporte gratuito. El transporte a título gratuito no está regido por las reglas del presente Capítulo, excepto que sea efectuado por un transportista que ofrece sus servicios al público en el curso de su actividad.", plainLanguageExplanation: "Establece el régimen de transporte gratuito. El transporte a título gratuito no está regido por las reglas del presente Capítulo, excepto que sea efectuado por un transportista que ofrece sus servicios al público en el curso de su actividad.", practicalEffects: ['En la práctica, este artículo rige transporte gratuito. El transporte a título gratuito no está regido por las reglas del presente Capítulo, excepto que sea efectuado por un transportista que ofrece sus ser'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transporte', 'gratuito', 'articulo 1282'], segments: [], amendments: [] },
  { id: 'ccyc-art-1283', lawId: 'codigo-civil-comercial', number: '1283', order: 1283, title: "Oferta al público", text: "Oferta al público. El transportista que ofrece sus servicios al público está obligado a aceptar los pedidos compatibles con los medios ordinarios de que dispone, excepto que exista un motivo serio de rechazo; y el pasajero o el cargador están obligados a seguir las instrucciones dadas por el transportista conforme a la ley o los reglamentos. Los transportes deben realizarse según el orden de los pedidos y, en caso de que haya varios simultáneos, debe darse preferencia a los de mayor recorrido.", plainLanguageExplanation: "Establece el régimen de oferta al público. El transportista que ofrece sus servicios al público está obligado a aceptar los pedidos compatibles con los medios ordinarios de que dispone, excepto que exista un motivo serio de rechazo; y el pasajero o el cargador están obligados a seguir las instrucciones dadas por el transp", practicalEffects: ['En la práctica, este artículo rige oferta al público. El transportista que ofrece sus servicios al público está obligado a aceptar los pedidos compatibles con los medios ordinarios de que dispone, excepto'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oferta', 'pblico', 'articulo 1283'], segments: [], amendments: [] },
  { id: 'ccyc-art-1284', lawId: 'codigo-civil-comercial', number: '1284', order: 1284, title: "Plazo", text: "Plazo. El transportista debe realizar el traslado convenido en el plazo pactado en el contrato o en los horarios establecidos y, en defecto de ambos, de acuerdo a los usos del lugar en que debe iniciarse el transporte.", plainLanguageExplanation: "Establece el régimen de plazo. El transportista debe realizar el traslado convenido en el plazo pactado en el contrato o en los horarios establecidos y, en defecto de ambos, de acuerdo a los usos del lugar en que debe iniciarse el transporte.", practicalEffects: ['En la práctica, este artículo rige plazo. El transportista debe realizar el traslado convenido en el plazo pactado en el contrato o en los horarios establecidos y, en defecto de ambos, de acue'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazoarticulo 1284'], segments: [], amendments: [] },
  { id: 'ccyc-art-1285', lawId: 'codigo-civil-comercial', number: '1285', order: 1285, title: "Pérdida total o parcial del flete por retraso", text: "Pérdida total o parcial del flete por retraso. Producido el retraso en el traslado de las cosas transportadas, si el transportista no prueba la causa ajena, pierde una parte del flete proporcional al retraso, de modo tal que pierde el total si el tiempo insumido es el doble del plazo en el que debió cumplirse. Lo dispuesto por este artículo no impide reclamar los mayores daños causados por el atraso.", plainLanguageExplanation: "Establece el régimen de pérdida total o parcial del flete por retraso. Producido el retraso en el traslado de las cosas transportadas, si el transportista no prueba la causa ajena, pierde una parte del flete proporcional al retraso, de modo tal que pierde el total si el tiempo insumido es el doble del plazo en el que debió cumplirse.", practicalEffects: ['En la práctica, este artículo rige pérdida total o parcial del flete por retraso. Producido el retraso en el traslado de las cosas transportadas, si el transportista no prueba la causa ajena, pierde una parte del flete proporcional'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prdida', 'total', 'parcial', 'flete', 'retraso', 'articulo 1285'], segments: [], amendments: [] },
  { id: 'ccyc-art-1286', lawId: 'codigo-civil-comercial', number: '1286', order: 1286, title: "Responsabilidad del transportista", text: "Responsabilidad del transportista. La responsabilidad del transportista por daños a las personas transportadas está sujeta a lo dispuesto en los artículos 1757 y siguientes. Si el transporte es de cosas, el transportista se excusa probando la causa ajena. El vicio propio de la cosa transportada es considerado causa ajena.", plainLanguageExplanation: "Establece el régimen de responsabilidad del transportista. La responsabilidad del transportista por daños a las personas transportadas está sujeta a lo dispuesto en los artículos 1757 y siguientes.", practicalEffects: ['En la práctica, este artículo rige responsabilidad del transportista. La responsabilidad del transportista por daños a las personas transportadas está sujeta a lo dispuesto en los artículos 1757 y siguientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'transportista', 'articulo 1286'], segments: [], amendments: [] },
  { id: 'ccyc-art-1287', lawId: 'codigo-civil-comercial', number: '1287', order: 1287, title: "Transporte sucesivo o combinado", text: "Transporte sucesivo o combinado. En los transportes sucesivos o combinados a ejecutar por varios transportistas, cada uno de ellos responde por los daños producidos durante su propio recorrido. Pero si el transporte es asumido por varios transportistas en un único contrato, o no se puede determinar dónde ocurre el daño, todos ellos responden solidariamente sin perjuicio de las acciones de reintegro. SECCION 2ª Transporte de personas", plainLanguageExplanation: "Establece el régimen de transporte sucesivo o combinado. En los transportes sucesivos o combinados a ejecutar por varios transportistas, cada uno de ellos responde por los daños producidos durante su propio recorrido.", practicalEffects: ['En la práctica, este artículo rige transporte sucesivo o combinado. En los transportes sucesivos o combinados a ejecutar por varios transportistas, cada uno de ellos responde por los daños producidos durante su propio recorrido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transporte', 'sucesivo', 'combinado', 'articulo 1287'], segments: [], amendments: [] },
  { id: 'ccyc-art-1288', lawId: 'codigo-civil-comercial', number: '1288', order: 1288, title: "Comienzo y fin del transporte", text: "Comienzo y fin del transporte. El transporte de personas comprende, además del traslado, las operaciones de embarco y desembarco.", plainLanguageExplanation: "Establece el régimen de comienzo y fin del transporte. El transporte de personas comprende, además del traslado, las operaciones de embarco y desembarco.", practicalEffects: ['En la práctica, este artículo rige comienzo y fin del transporte. El transporte de personas comprende, además del traslado, las operaciones de embarco y desembarco.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comienzo', 'transporte', 'articulo 1288'], segments: [], amendments: [] },
  { id: 'ccyc-art-1289', lawId: 'codigo-civil-comercial', number: '1289', order: 1289, title: "Obligaciones del transportista", text: "Obligaciones del transportista. Son obligaciones del transportista respecto del pasajero: a) proveerle el lugar para viajar que se ha convenido o el disponible reglamentariamente habilitado; b) trasladarlo al lugar convenido; c) garantizar su seguridad; d) llevar su equipaje.", plainLanguageExplanation: "Establece el régimen de obligaciones del transportista. Son obligaciones del transportista respecto del pasajero: a) proveerle el lugar para viajar que se ha convenido o el disponible reglamentariamente habilitado; b) trasladarlo al lugar convenido; c) garantizar su seguridad; d) llevar su equipaje.", practicalEffects: ['En la práctica, este artículo rige obligaciones del transportista. Son obligaciones del transportista respecto del pasajero: a) proveerle el lugar para viajar que se ha convenido o el disponible reglamentariamente hab'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'transportista', 'articulo 1289'], segments: [], amendments: [] },
  { id: 'ccyc-art-1290', lawId: 'codigo-civil-comercial', number: '1290', order: 1290, title: "Obligaciones del pasajero", text: "Obligaciones del pasajero. El pasajero está obligado a: a) pagar el precio pactado; b) presentarse en el lugar y momentos convenidos para iniciar el viaje; c) cumplir las disposiciones administrativas, observar los reglamentos establecidos por el transportista para el mejor orden durante el viaje y obedecer las órdenes del porteador o de sus representantes impartidas con la misma finalidad; d) acondicionar su equipaje, el que debe ajustarse a las medidas y peso reglamentarios.", plainLanguageExplanation: "Establece el régimen de obligaciones del pasajero. El pasajero está obligado a: a) pagar el precio pactado; b) presentarse en el lugar y momentos convenidos para iniciar el viaje; c) cumplir las disposiciones administrativas, observar los reglamentos establecidos por el transportista para el mejor orden durante el viaje y obedece", practicalEffects: ['En la práctica, este artículo rige obligaciones del pasajero. El pasajero está obligado a: a) pagar el precio pactado; b) presentarse en el lugar y momentos convenidos para iniciar el viaje; c) cumplir las dispos'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'pasajero', 'articulo 1290'], segments: [], amendments: [] },
  { id: 'ccyc-art-1291', lawId: 'codigo-civil-comercial', number: '1291', order: 1291, title: "Extensión de la responsabilidad", text: "Extensión de la responsabilidad. Además de su responsabilidad por incumplimiento del contrato o retraso en su ejecución, el transportista responde por los siniestros que afecten a la persona del pasajero y por la avería o pérdida de sus cosas.", plainLanguageExplanation: "Establece el régimen de extensión de la responsabilidad. Además de su responsabilidad por incumplimiento del contrato o retraso en su ejecución, el transportista responde por los siniestros que afecten a la persona del pasajero y por la avería o pérdida de sus cosas.", practicalEffects: ['En la práctica, este artículo rige extensión de la responsabilidad. Además de su responsabilidad por incumplimiento del contrato o retraso en su ejecución, el transportista responde por los siniestros que afecten a la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extensin', 'responsabilidad', 'articulo 1291'], segments: [], amendments: [] },
  { id: 'ccyc-art-1292', lawId: 'codigo-civil-comercial', number: '1292', order: 1292, title: "Cláusulas limitativas de la responsabilidad", text: "Cláusulas limitativas de la responsabilidad. Las cláusulas que limitan la responsabilidad del transportista de personas por muerte o daños corporales se tienen por no escritas.", plainLanguageExplanation: "Establece el régimen de cláusulas limitativas de la responsabilidad. Las cláusulas que limitan la responsabilidad del transportista de personas por muerte o daños corporales se tienen por no escritas.", practicalEffects: ['En la práctica, este artículo rige cláusulas limitativas de la responsabilidad. Las cláusulas que limitan la responsabilidad del transportista de personas por muerte o daños corporales se tienen por no escritas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusulas', 'limitativas', 'responsabilidad', 'articulo 1292'], segments: [], amendments: [] },
  { id: 'ccyc-art-1293', lawId: 'codigo-civil-comercial', number: '1293', order: 1293, title: "Responsabilidad por el equipaje", text: "Responsabilidad por el equipaje. Las disposiciones relativas a la responsabilidad del transportista de cosas por la pérdida o deterioro de las cosas transportadas, se aplican a la pérdida o deterioro del equipaje que el pasajero lleva consigo, con la salvedad de lo previsto en el artículo 1294.", plainLanguageExplanation: "Establece el régimen de responsabilidad por el equipaje. Las disposiciones relativas a la responsabilidad del transportista de cosas por la pérdida o deterioro de las cosas transportadas, se aplican a la pérdida o deterioro del equipaje que el pasajero lleva consigo, con la salvedad de lo previsto en el artículo 1294.", practicalEffects: ['En la práctica, este artículo rige responsabilidad por el equipaje. Las disposiciones relativas a la responsabilidad del transportista de cosas por la pérdida o deterioro de las cosas transportadas, se aplican a la pér'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'equipaje', 'articulo 1293'], segments: [], amendments: [] },
  { id: 'ccyc-art-1294', lawId: 'codigo-civil-comercial', number: '1294', order: 1294, title: "Cosas de valor", text: "Cosas de valor. El transportista no responde por pérdida o daños sufridos por objetos de valor extraordinario que el pasajero lleve consigo y no haya declarado antes del viaje o al comienzo de éste. Tampoco es responsable por la pérdida del equipaje de mano y de los demás efectos que hayan quedado bajo la custodia del pasajero, a menos que éste pruebe la culpa del transportista.", plainLanguageExplanation: "Establece el régimen de cosas de valor. El transportista no responde por pérdida o daños sufridos por objetos de valor extraordinario que el pasajero lleve consigo y no haya declarado antes del viaje o al comienzo de éste.", practicalEffects: ['En la práctica, este artículo rige cosas de valor. El transportista no responde por pérdida o daños sufridos por objetos de valor extraordinario que el pasajero lleve consigo y no haya declarado antes del viaje o al comienzo de éste.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cosas', 'valor', 'articulo 1294'], segments: [], amendments: [] },
  { id: 'ccyc-art-1295', lawId: 'codigo-civil-comercial', number: '1295', order: 1295, title: "Interrupción del transporte sucesivo", text: "Interrupción del transporte sucesivo. Sin perjuicio de la aplicación del artículo 1287, primer párrafo, los daños originados por interrupción del viaje se deben determinar en razón del trayecto total. SECCION 3ª Transporte de cosas", plainLanguageExplanation: "Establece el régimen de interrupción del transporte sucesivo. Sin perjuicio de la aplicación del artículo 1287, primer párrafo, los daños originados por interrupción del viaje se deben determinar en razón del trayecto total.", practicalEffects: ['En la práctica, este artículo rige interrupción del transporte sucesivo. Sin perjuicio de la aplicación del artículo 1287, primer párrafo, los daños originados por interrupción del viaje se deben determinar en razón del trayecto total.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interrupcin', 'transporte', 'sucesivo', 'articulo 1295'], segments: [], amendments: [] },
  { id: 'ccyc-art-1296', lawId: 'codigo-civil-comercial', number: '1296', order: 1296, title: "Obligaciones del cargador", text: "Obligaciones del cargador. El cargador debe declarar el contenido de la carga, identificar los bultos externamente, presentar la carga con embalaje adecuado, indicar el destino y el destinatario, y entregar al transportista la documentación requerida para realizarlo. Si se requieren documentos especiales, el cargador debe entregarlos al porteador al mismo tiempo que las cosas a transportar.", plainLanguageExplanation: "Establece el régimen de obligaciones del cargador. El cargador debe declarar el contenido de la carga, identificar los bultos externamente, presentar la carga con embalaje adecuado, indicar el destino y el destinatario, y entregar al transportista la documentación requerida para realizarlo.", practicalEffects: ['En la práctica, este artículo rige obligaciones del cargador. El cargador debe declarar el contenido de la carga, identificar los bultos externamente, presentar la carga con embalaje adecuado, indicar el destino'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'cargador', 'articulo 1296'], segments: [], amendments: [] },
  { id: 'ccyc-art-1297', lawId: 'codigo-civil-comercial', number: '1297', order: 1297, title: "Responsabilidad del cargador", text: "Responsabilidad del cargador. El cargador es responsable de los daños que sufran el transportista, otros cargadores o terceros, que deriven de la omisión o la inexactitud de las indicaciones o de la falta de entrega o de la irregularidad de la documentación.", plainLanguageExplanation: "Establece el régimen de responsabilidad del cargador. El cargador es responsable de los daños que sufran el transportista, otros cargadores o terceros, que deriven de la omisión o la inexactitud de las indicaciones o de la falta de entrega o de la irregularidad de la documentación.", practicalEffects: ['En la práctica, este artículo rige responsabilidad del cargador. El cargador es responsable de los daños que sufran el transportista, otros cargadores o terceros, que deriven de la omisión o la inexactitud de las in'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'cargador', 'articulo 1297'], segments: [], amendments: [] },
  { id: 'ccyc-art-1298', lawId: 'codigo-civil-comercial', number: '1298', order: 1298, title: "Carta de porte", text: "Carta de porte. El transportista tiene derecho a requerir del cargador que suscriba un documento que contenga las indicaciones enunciadas en el artículo 1296 y las estipulaciones convenidas para el transporte. Su emisión importa recibo de la carga.", plainLanguageExplanation: "Establece el régimen de carta de porte. El transportista tiene derecho a requerir del cargador que suscriba un documento que contenga las indicaciones enunciadas en el artículo 1296 y las estipulaciones convenidas para el transporte.", practicalEffects: ['En la práctica, este artículo rige carta de porte. El transportista tiene derecho a requerir del cargador que suscriba un documento que contenga las indicaciones enunciadas en el artículo 1296 y las estipulaciones convenidas para el transporte.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carta', 'porte', 'articulo 1298'], segments: [], amendments: [] },
  { id: 'ccyc-art-1299', lawId: 'codigo-civil-comercial', number: '1299', order: 1299, title: "Segundo ejemplar", text: "Segundo ejemplar. El cargador tiene derecho a exigir al porteador que suscriba y le entregue copia de la carta de porte. Este documento se llama segundo ejemplar de la carta de porte y puede ser nominativo, a la orden o al portador. Si el transportista ha librado el segundo ejemplar de la carta de porte a la orden, los derechos nacidos del contrato frente a aquél, son transmisibles por endoso.", plainLanguageExplanation: "Establece el régimen de segundo ejemplar. El cargador tiene derecho a exigir al porteador que suscriba y le entregue copia de la carta de porte.", practicalEffects: ['En la práctica, este artículo rige segundo ejemplar. El cargador tiene derecho a exigir al porteador que suscriba y le entregue copia de la carta de porte.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['segundo', 'ejemplar', 'articulo 1299'], segments: [], amendments: [] },
  { id: 'ccyc-art-1300', lawId: 'codigo-civil-comercial', number: '1300', order: 1300, title: "Guía", text: "Guía. Si no hay carta de porte, el cargador tiene derecho a exigir al transportista que le entregue un recibo de carga, denominado guía, con el mismo contenido de aquélla.", plainLanguageExplanation: "Establece el régimen de guía. Si no hay carta de porte, el cargador tiene derecho a exigir al transportista que le entregue un recibo de carga, denominado guía, con el mismo contenido de aquélla.", practicalEffects: ['En la práctica, este artículo rige guía. Si no hay carta de porte, el cargador tiene derecho a exigir al transportista que le entregue un recibo de carga, denominado guía, con el mismo conten'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['guaarticulo 1300'], segments: [], amendments: [] },
  { id: 'ccyc-art-1301', lawId: 'codigo-civil-comercial', number: '1301', order: 1301, title: "Inoponibilidad", text: "Inoponibilidad. Las estipulaciones no contenidas en el segundo ejemplar de la carta de porte o en la guía, no son oponibles a los terceros portadores de buena fe. Ese documento debe ser entregado al transportista contra la entrega por éste de la carga transportada.", plainLanguageExplanation: "Establece el régimen de inoponibilidad. Las estipulaciones no contenidas en el segundo ejemplar de la carta de porte o en la guía, no son oponibles a los terceros portadores de buena fe.", practicalEffects: ['En la práctica, este artículo rige inoponibilidad. Las estipulaciones no contenidas en el segundo ejemplar de la carta de porte o en la guía, no son oponibles a los terceros portadores de buena fe.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inoponibilidadarticulo 1301'], segments: [], amendments: [] },
  { id: 'ccyc-art-1302', lawId: 'codigo-civil-comercial', number: '1302', order: 1302, title: "Disposición de la carga", text: "Disposición de la carga. Si no se ha extendido el segundo ejemplar de la carta de porte ni la guía, el cargador tiene la disposición de la carga y puede modificar las instrucciones dadas al transportista, con obligación de reembolsar los gastos y resarcir los daños derivados de ese cambio.", plainLanguageExplanation: "Establece el régimen de disposición de la carga. Si no se ha extendido el segundo ejemplar de la carta de porte ni la guía, el cargador tiene la disposición de la carga y puede modificar las instrucciones dadas al transportista, con obligación de reembolsar los gastos y resarcir los daños derivados de ese cambio.", practicalEffects: ['En la práctica, este artículo rige disposición de la carga. Si no se ha extendido el segundo ejemplar de la carta de porte ni la guía, el cargador tiene la disposición de la carga y puede modificar las instrucc'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposicin', 'carga', 'articulo 1302'], segments: [], amendments: [] },
  { id: 'ccyc-art-1303', lawId: 'codigo-civil-comercial', number: '1303', order: 1303, title: "Portador del segundo ejemplar", text: "Portador del segundo ejemplar. Cuando el transportista ha librado segundo ejemplar de la carta de porte o guía, sólo el portador legitimado de cualquiera de dichos documentos tiene la disposición de la carga y puede impartir instrucciones al transportista, las cuales se deben anotar en el instrumento y ser suscriptas por el transportista.", plainLanguageExplanation: "Establece el régimen de portador del segundo ejemplar. Cuando el transportista ha librado segundo ejemplar de la carta de porte o guía, sólo el portador legitimado de cualquiera de dichos documentos tiene la disposición de la carga y puede impartir instrucciones al transportista, las cuales se deben anotar en el instrumento y ser sus", practicalEffects: ['En la práctica, este artículo rige portador del segundo ejemplar. Cuando el transportista ha librado segundo ejemplar de la carta de porte o guía, sólo el portador legitimado de cualquiera de dichos documentos tiene'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['portador', 'segundo', 'ejemplar', 'articulo 1303'], segments: [], amendments: [] },
  { id: 'ccyc-art-1304', lawId: 'codigo-civil-comercial', number: '1304', order: 1304, title: "Derechos del destinatario", text: "Derechos del destinatario. Los derechos nacidos del contrato de transporte corresponden al destinatario desde que las cosas llegan a destino, o desde que, vencido el plazo del transporte, haya requerido la entrega al transportista. Sin embargo, el destinatario no puede ejercer tales derechos sino contra el pago al transportista de sus créditos derivados del transporte.", plainLanguageExplanation: "Establece el régimen de derechos del destinatario. Los derechos nacidos del contrato de transporte corresponden al destinatario desde que las cosas llegan a destino, o desde que, vencido el plazo del transporte, haya requerido la entrega al transportista.", practicalEffects: ['En la práctica, este artículo rige derechos del destinatario. Los derechos nacidos del contrato de transporte corresponden al destinatario desde que las cosas llegan a destino, o desde que, vencido el plazo del t'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'destinatario', 'articulo 1304'], segments: [], amendments: [] },
  { id: 'ccyc-art-1305', lawId: 'codigo-civil-comercial', number: '1305', order: 1305, title: "Puesta a disposición", text: "Puesta a disposición. El transportista debe poner la carga a disposición del destinatario en el lugar, en el plazo y con las modalidades convenidas en el contrato o, en su defecto, por los usos. Si el cargador ha librado una carta de porte, ésta debe ser exhibida y entregada al porteador. El tenedor del segundo ejemplar de la carta de porte o de la guía al portador o a la orden, debe restituir el documento al transportista en el momento de la entrega de la carga.", plainLanguageExplanation: "Establece el régimen de puesta a disposición. El transportista debe poner la carga a disposición del destinatario en el lugar, en el plazo y con las modalidades convenidas en el contrato o, en su defecto, por los usos.", practicalEffects: ['En la práctica, este artículo rige puesta a disposición. El transportista debe poner la carga a disposición del destinatario en el lugar, en el plazo y con las modalidades convenidas en el contrato o, en su defecto, por los usos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['puesta', 'disposicin', 'articulo 1305'], segments: [], amendments: [] },
  { id: 'ccyc-art-1306', lawId: 'codigo-civil-comercial', number: '1306', order: 1306, title: "Entrega", text: "Entrega. El transportista está obligado a entregar la carga en el mismo estado en que la recibió, excepto causa ajena. Si la ha recibido sin reservas, se presume que ella no tenía vicios aparentes y estaba bien acondicionada para el transporte. El destinatario no está obligado a recibir cosas con daños que impidan el uso o consumo que les son propios.", plainLanguageExplanation: "Establece el régimen de entrega. El transportista está obligado a entregar la carga en el mismo estado en que la recibió, excepto causa ajena.", practicalEffects: ['En la práctica, este artículo rige entrega. El transportista está obligado a entregar la carga en el mismo estado en que la recibió, excepto causa ajena.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entregaarticulo 1306'], segments: [], amendments: [] },
  { id: 'ccyc-art-1307', lawId: 'codigo-civil-comercial', number: '1307', order: 1307, title: "Impedimentos y retardo en la ejecución del transporte", text: "Impedimentos y retardo en la ejecución del transporte. Si el comienzo o la continuación del transporte son impedidos o excesivamente retrasados por causa no imputable al porteador, éste debe informar inmediatamente al cargador y pedirle instrucciones. Está obligado a la custodia de la carga. Si las circunstancias imposibilitan el pedido de instrucciones, el transportista puede depositar las cosas y, si están sujetas a rápido deterioro o son perecederas, puede hacerlas vender para que no pierdan su valor.", plainLanguageExplanation: "Establece el régimen de impedimentos y retardo en la ejecución del transporte. Si el comienzo o la continuación del transporte son impedidos o excesivamente retrasados por causa no imputable al porteador, éste debe informar inmediatamente al cargador y pedirle instrucciones.", practicalEffects: ['En la práctica, este artículo rige impedimentos y retardo en la ejecución del transporte. Si el comienzo o la continuación del transporte son impedidos o excesivamente retrasados por causa no imputable al porteador, éste debe informar inmediatamente al cargador y pedirle instrucciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impedimentos', 'retardo', 'ejecucin', 'transporte', 'articulo 1307'], segments: [], amendments: [] },
  { id: 'ccyc-art-1308', lawId: 'codigo-civil-comercial', number: '1308', order: 1308, title: "Impedimentos para la entrega", text: "Impedimentos para la entrega. Si el destinatario no puede ser encontrado o se niega a recibir las cosas transportadas o demora su recepción, el porteador debe requerir inmediatamente instrucciones al cargador y se aplican las soluciones previstas en el artículo 1307.", plainLanguageExplanation: "Establece el régimen de impedimentos para la entrega. Si el destinatario no puede ser encontrado o se niega a recibir las cosas transportadas o demora su recepción, el porteador debe requerir inmediatamente instrucciones al cargador y se aplican las soluciones previstas en el artículo 1307.", practicalEffects: ['En la práctica, este artículo rige impedimentos para la entrega. Si el destinatario no puede ser encontrado o se niega a recibir las cosas transportadas o demora su recepción, el porteador debe requerir inmediatamen'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impedimentos', 'para', 'entrega', 'articulo 1308'], segments: [], amendments: [] },
  { id: 'ccyc-art-1309', lawId: 'codigo-civil-comercial', number: '1309', order: 1309, title: "Responsabilidad del transportista frente al cargador", text: "Responsabilidad del transportista frente al cargador. El porteador que entregue las cosas al destinatario sin cobrar los créditos propios o los que el cargador le haya encomendado cobrar contra entrega de la carga, o sin exigir el depósito de la suma convenida, es responsable frente al cargador por lo que le sea debido y no puede dirigirse contra él para el pago de sus propias acreencias. Mantiene su acción contra el destinatario.", plainLanguageExplanation: "Establece el régimen de responsabilidad del transportista frente al cargador. El porteador que entregue las cosas al destinatario sin cobrar los créditos propios o los que el cargador le haya encomendado cobrar contra entrega de la carga, o sin exigir el depósito de la suma convenida, es responsable frente al cargador por lo que le sea debido y no puede di", practicalEffects: ['En la práctica, este artículo rige responsabilidad del transportista frente al cargador. El porteador que entregue las cosas al destinatario sin cobrar los créditos propios o los que el cargador le haya encomendado cobrar contra entrega de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'transportista', 'frente', 'cargador', 'articulo 1309'], segments: [], amendments: [] },
  { id: 'ccyc-art-1310', lawId: 'codigo-civil-comercial', number: '1310', order: 1310, title: "Responsabilidad por culpa", text: "Responsabilidad por culpa. Si se trata de cosas frágiles, mal acondicionadas para el transporte, sujetas a fácil deterioro, de animales o de transportes especiales, el transportista puede convenir que sólo responde si se prueba su culpa. Esta convención no puede estar incluida en una cláusula general predispuesta.", plainLanguageExplanation: "Establece el régimen de responsabilidad por culpa. Si se trata de cosas frágiles, mal acondicionadas para el transporte, sujetas a fácil deterioro, de animales o de transportes especiales, el transportista puede convenir que sólo responde si se prueba su culpa.", practicalEffects: ['En la práctica, este artículo rige responsabilidad por culpa. Si se trata de cosas frágiles, mal acondicionadas para el transporte, sujetas a fácil deterioro, de animales o de transportes especiales, el transport'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'culpa', 'articulo 1310'], segments: [], amendments: [] },
  { id: 'ccyc-art-1311', lawId: 'codigo-civil-comercial', number: '1311', order: 1311, title: "Cálculo del daño", text: "Cálculo del daño. La indemnización por pérdida o avería de las cosas es el valor de éstas o el de su menoscabo, en el tiempo y el lugar en que se entregaron o debieron ser entregadas al destinatario.", plainLanguageExplanation: "Establece el régimen de cálculo del daño. La indemnización por pérdida o avería de las cosas es el valor de éstas o el de su menoscabo, en el tiempo y el lugar en que se entregaron o debieron ser entregadas al destinatario.", practicalEffects: ['En la práctica, este artículo rige cálculo del daño. La indemnización por pérdida o avería de las cosas es el valor de éstas o el de su menoscabo, en el tiempo y el lugar en que se entregaron o debieron'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clculo', 'dao', 'articulo 1311'], segments: [], amendments: [] },
  { id: 'ccyc-art-1312', lawId: 'codigo-civil-comercial', number: '1312', order: 1312, title: "Pérdida natural", text: "Pérdida natural. En el transporte de cosas que, por su naturaleza, están sujetas a disminución en el peso o en la medida durante el transporte, el transportista sólo responde por las disminuciones que excedan la pérdida natural. También responde si el cargador o el destinatario prueban que la disminución no ha ocurrido por la naturaleza de las cosas o que, por las circunstancias del caso, no pudo alcanzar la magnitud comprobada.", plainLanguageExplanation: "Establece el régimen de pérdida natural. En el transporte de cosas que, por su naturaleza, están sujetas a disminución en el peso o en la medida durante el transporte, el transportista sólo responde por las disminuciones que excedan la pérdida natural.", practicalEffects: ['En la práctica, este artículo rige pérdida natural. En el transporte de cosas que, por su naturaleza, están sujetas a disminución en el peso o en la medida durante el transporte, el transportista sólo r'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prdida', 'natural', 'articulo 1312'], segments: [], amendments: [] },
  { id: 'ccyc-art-1313', lawId: 'codigo-civil-comercial', number: '1313', order: 1313, title: "Limitación de la responsabilidad", text: "Limitación de la responsabilidad. Prohibición. Los que realizan habitualmente servicios de transporte no pueden limitar las reglas de responsabilidad precedentes, excepto en el caso del artículo 1310.", plainLanguageExplanation: "Establece el régimen de limitación de la responsabilidad. Prohibición.", practicalEffects: ['En la práctica, este artículo rige limitación de la responsabilidad. Prohibición.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['limitacin', 'responsabilidad', 'articulo 1313'], segments: [], amendments: [] },
  { id: 'ccyc-art-1314', lawId: 'codigo-civil-comercial', number: '1314', order: 1314, title: "Comprobación de las cosas antes de la entrega", text: "Comprobación de las cosas antes de la entrega. El destinatario tiene derecho a hacer comprobar, a su costo, antes de la recepción de las cosas, su identidad y estado. Si existen pérdidas o averías, el transportista debe reembolsar los gastos. El porteador puede exigir al destinatario la apertura y el reconocimiento de la carga; y si éste rehúsa u omite hacerlo, el porteador queda liberado de toda responsabilidad, excepto dolo.", plainLanguageExplanation: "Establece el régimen de comprobación de las cosas antes de la entrega. El destinatario tiene derecho a hacer comprobar, a su costo, antes de la recepción de las cosas, su identidad y estado.", practicalEffects: ['En la práctica, este artículo rige comprobación de las cosas antes de la entrega. El destinatario tiene derecho a hacer comprobar, a su costo, antes de la recepción de las cosas, su identidad y estado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comprobacin', 'cosas', 'antes', 'entrega', 'articulo 1314'], segments: [], amendments: [] },
  { id: 'ccyc-art-1315', lawId: 'codigo-civil-comercial', number: '1315', order: 1315, title: "Efectos de la recepción de las cosas transportadas", text: "Efectos de la recepción de las cosas transportadas. La recepción por el destinatario de las cosas transportadas y el pago de lo debido al transportista extinguen las acciones derivadas del contrato, excepto dolo. Sólo subsisten las acciones por pérdida parcial o avería no reconocibles en el momento de la entrega, las cuales deben ser deducidas dentro de los cinco días posteriores a la recepción.", plainLanguageExplanation: "Establece el régimen de efectos de la recepción de las cosas transportadas. La recepción por el destinatario de las cosas transportadas y el pago de lo debido al transportista extinguen las acciones derivadas del contrato, excepto dolo.", practicalEffects: ['En la práctica, este artículo rige efectos de la recepción de las cosas transportadas. La recepción por el destinatario de las cosas transportadas y el pago de lo debido al transportista extinguen las acciones derivadas del contrato, excepto dolo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'recepcin', 'cosas', 'transportadas', 'articulo 1315'], segments: [], amendments: [] },
  { id: 'ccyc-art-1316', lawId: 'codigo-civil-comercial', number: '1316', order: 1316, title: "Culpa del cargador o de un tercero", text: "Culpa del cargador o de un tercero. Si el transporte no pudo ser iniciado o completado o la entrega no puede ser efectuada por el hecho del cargador, o de un portador legitimado del segundo ejemplar de la carta de porte o de la guía, o del destinatario, el transportista tiene derecho al precio o a una parte proporcional de éste, según sea el caso, y al reembolso de los gastos adicionales en que haya incurrido.", plainLanguageExplanation: "Establece el régimen de culpa del cargador o de un tercero. Si el transporte no pudo ser iniciado o completado o la entrega no puede ser efectuada por el hecho del cargador, o de un portador legitimado del segundo ejemplar de la carta de porte o de la guía, o del destinatario, el transportista tiene derecho al precio o a una parte proporc", practicalEffects: ['En la práctica, este artículo rige culpa del cargador o de un tercero. Si el transporte no pudo ser iniciado o completado o la entrega no puede ser efectuada por el hecho del cargador, o de un portador legitimado del segu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['culpa', 'cargador', 'tercero', 'articulo 1316'], segments: [], amendments: [] },
  { id: 'ccyc-art-1317', lawId: 'codigo-civil-comercial', number: '1317', order: 1317, title: "Transporte con reexpedición de las cosas", text: "Transporte con reexpedición de las cosas. Si el transportista se obliga a entregar la carga a otro porteador y no acepta una carta de porte hasta un destino diferente al de tal entrega, se presume que sus responsabilidades como transportista concluyen con ella, sin otras obligaciones adicionales que la de emplear una razonable diligencia en la contratación del transportista siguiente.", plainLanguageExplanation: "Establece el régimen de transporte con reexpedición de las cosas. Si el transportista se obliga a entregar la carga a otro porteador y no acepta una carta de porte hasta un destino diferente al de tal entrega, se presume que sus responsabilidades como transportista concluyen con ella, sin otras obligaciones adicionales que la de emplear una raz", practicalEffects: ['En la práctica, este artículo rige transporte con reexpedición de las cosas. Si el transportista se obliga a entregar la carga a otro porteador y no acepta una carta de porte hasta un destino diferente al de tal entrega, se pre'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transporte', 'reexpedicin', 'cosas', 'articulo 1317'], segments: [], amendments: [] },
  { id: 'ccyc-art-1318', lawId: 'codigo-civil-comercial', number: '1318', order: 1318, title: "Representación en el transporte sucesivo", text: "Representación en el transporte sucesivo. Cada transportista sucesivo tiene el derecho de hacer constar en la carta de porte, o en un documento separado, el estado en que ha recibido las cosas transportadas. El último transportista representa a los demás para el cobro de sus créditos y el ejercicio de sus derechos sobre las cargas transportadas. CAPITULO 8 Mandato", plainLanguageExplanation: "Establece el régimen de representación en el transporte sucesivo. Cada transportista sucesivo tiene el derecho de hacer constar en la carta de porte, o en un documento separado, el estado en que ha recibido las cosas transportadas.", practicalEffects: ['En la práctica, este artículo rige representación en el transporte sucesivo. Cada transportista sucesivo tiene el derecho de hacer constar en la carta de porte, o en un documento separado, el estado en que ha recibido las cosas transportadas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representacin', 'transporte', 'sucesivo', 'articulo 1318'], segments: [], amendments: [] },
  { id: 'ccyc-art-1319', lawId: 'codigo-civil-comercial', number: '1319', order: 1319, title: "Definición", text: "Definición. Hay contrato de mandato cuando una parte se obliga a realizar uno o más actos jurídicos en interés de otra. El mandato puede ser conferido y aceptado expresa o tácitamente. Si una persona sabe que alguien está haciendo algo en su interés, y no lo impide, pudiendo hacerlo, se entiende que ha conferido tácitamente mandato. La ejecución del mandato implica su aceptación aun sin mediar declaración expresa sobre ella.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de mandato cuando una parte se obliga a realizar uno o más actos jurídicos en interés de otra.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de mandato cuando una parte se obliga a realizar uno o más actos jurídicos en interés de otra.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1319'], segments: [], amendments: [] },
  { id: 'ccyc-art-1320', lawId: 'codigo-civil-comercial', number: '1320', order: 1320, title: "Representación", text: "Representación. Si el mandante confiere poder para ser representado, le son aplicables las disposiciones de los artículos 362 y siguientes. Aun cuando el mandato no confiera poder de representación, se aplican las disposiciones citadas a las relaciones entre mandante y mandatario, en todo lo que no resulten modificadas en este Capítulo.", plainLanguageExplanation: "Establece el régimen de representación. Si el mandante confiere poder para ser representado, le son aplicables las disposiciones de los artículos 362 y siguientes.", practicalEffects: ['En la práctica, este artículo rige representación. Si el mandante confiere poder para ser representado, le son aplicables las disposiciones de los artículos 362 y siguientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representacinarticulo 1320'], segments: [], amendments: [] },
  { id: 'ccyc-art-1321', lawId: 'codigo-civil-comercial', number: '1321', order: 1321, title: "Mandato sin representación", text: "Mandato sin representación. Si el mandante no otorga poder de representación, el mandatario actúa en nombre propio pero en interés del mandante, quien no queda obligado directamente respecto del tercero, ni éste respecto del mandante. El mandante puede subrogarse en las acciones que tiene el mandatario contra el tercero, e igualmente el tercero en las acciones que pueda ejercer el mandatario contra el mandante.", plainLanguageExplanation: "Establece el régimen de mandato sin representación. Si el mandante no otorga poder de representación, el mandatario actúa en nombre propio pero en interés del mandante, quien no queda obligado directamente respecto del tercero, ni éste respecto del mandante.", practicalEffects: ['En la práctica, este artículo rige mandato sin representación. Si el mandante no otorga poder de representación, el mandatario actúa en nombre propio pero en interés del mandante, quien no queda obligado directame'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato', 'representacin', 'articulo 1321'], segments: [], amendments: [] },
  { id: 'ccyc-art-1322', lawId: 'codigo-civil-comercial', number: '1322', order: 1322, title: "Onerosidad", text: "Onerosidad. El mandato se presume oneroso. A falta de acuerdo sobre la retribución, la remuneración es la que establecen las disposiciones legales o reglamentarias aplicables, o el uso. A falta de ambos, debe ser determinada por el juez.", plainLanguageExplanation: "Establece el régimen de onerosidad. El mandato se presume oneroso.", practicalEffects: ['En la práctica, este artículo rige onerosidad. El mandato se presume oneroso.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['onerosidadarticulo 1322'], segments: [], amendments: [] },
  { id: 'ccyc-art-1323', lawId: 'codigo-civil-comercial', number: '1323', order: 1323, title: "Capacidad", text: "Capacidad. El mandato puede ser conferido a una persona incapaz, pero ésta puede oponer la nulidad del contrato si es demandado por inejecución de las obligaciones o por rendición de cuentas, excepto la acción de restitución de lo que se ha convertido en provecho suyo.", plainLanguageExplanation: "Establece el régimen de capacidad. El mandato puede ser conferido a una persona incapaz, pero ésta puede oponer la nulidad del contrato si es demandado por inejecución de las obligaciones o por rendición de cuentas, excepto la acción de restitución de lo que se ha convertido en provecho suyo.", practicalEffects: ['En la práctica, este artículo rige capacidad. El mandato puede ser conferido a una persona incapaz, pero ésta puede oponer la nulidad del contrato si es demandado por inejecución de las obligacion'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capacidadarticulo 1323'], segments: [], amendments: [] },
  { id: 'ccyc-art-1324', lawId: 'codigo-civil-comercial', number: '1324', order: 1324, title: "Obligaciones del mandatario", text: "Obligaciones del mandatario. El mandatario está obligado a: a) cumplir los actos comprendidos en el mandato, conforme a las instrucciones dadas por el mandante y a la naturaleza del negocio que constituye su objeto, con el cuidado que pondría en los asuntos propios o, en su caso, el exigido por las reglas de su profesión, o por los usos del lugar de ejecución; b) dar aviso inmediato al mandante de cualquier circunstancia sobreviniente que razonablemente aconseje apartarse de las instrucciones recibidas, requiriendo nuevas instrucciones o ratificación de las anteriores, y adoptar las medidas indispensables y urgentes; c) informar sin demora al mandante de todo conflicto de intereses y de toda otra circunstancia que pueda motivar la modificación o la revocación del mandato; d) mantener en reserva toda información que adquiera con motivo del mandato que, por su naturaleza o circunstancias, no está destinada a ser divulgada; e) dar aviso al mandante de todo valor que haya recibido en razón del mandato, y ponerlo a disposición de aquél; f) rendir cuenta de su gestión en las oportunidades convenidas o a la extinción del mandato; g) entregar al mandante las ganancias derivadas del negocio, con los intereses moratorios, de las sumas de dinero que haya utilizado en provecho propio; h) informar en cualquier momento, a requerimiento del mandante, sobre la ejecución del mandato; i) exhibir al mandante toda la documentación relacionada con la gestión encomendada, y entregarle la que corresponde según las circunstancias. Si el negocio encargado al mandatario fuese de los que, por su oficio o su modo de vivir, acepta él regularmente, aun cuando se excuse del encargo, debe tomar las providencias conservatorias urgentes que requiera el negocio que se le encomienda.", plainLanguageExplanation: "Establece el régimen de obligaciones del mandatario. El mandatario está obligado a: a) cumplir los actos comprendidos en el mandato, conforme a las instrucciones dadas por el mandante y a la naturaleza del negocio que constituye su objeto, con el cuidado que pondría en los asuntos propios o, en su caso, el exigido por las reglas de", practicalEffects: ['En la práctica, este artículo rige obligaciones del mandatario. El mandatario está obligado a: a) cumplir los actos comprendidos en el mandato, conforme a las instrucciones dadas por el mandante y a la naturaleza d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'mandatario', 'articulo 1324'], segments: [], amendments: [] },
  { id: 'ccyc-art-1325', lawId: 'codigo-civil-comercial', number: '1325', order: 1325, title: "Conflicto de intereses", text: "Conflicto de intereses. Si media conflicto de intereses entre el mandante y el mandatario, éste debe posponer los suyos en la ejecución del mandato, o renunciar. La obtención, en el desempeño del cargo, de un beneficio no autorizado por el mandante, hace perder al mandatario su derecho a la retribución.", plainLanguageExplanation: "Establece el régimen de conflicto de intereses. Si media conflicto de intereses entre el mandante y el mandatario, éste debe posponer los suyos en la ejecución del mandato, o renunciar.", practicalEffects: ['En la práctica, este artículo rige conflicto de intereses. Si media conflicto de intereses entre el mandante y el mandatario, éste debe posponer los suyos en la ejecución del mandato, o renunciar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conflicto', 'intereses', 'articulo 1325'], segments: [], amendments: [] },
  { id: 'ccyc-art-1326', lawId: 'codigo-civil-comercial', number: '1326', order: 1326, title: "Mandato a varias personas", text: "Mandato a varias personas. Si el mandato se confiere a varias personas sin estipular expresamente la forma o el orden de su actuación, se entiende que pueden desempeñarse conjunta o separadamente.", plainLanguageExplanation: "Establece el régimen de mandato a varias personas. Si el mandato se confiere a varias personas sin estipular expresamente la forma o el orden de su actuación, se entiende que pueden desempeñarse conjunta o separadamente.", practicalEffects: ['En la práctica, este artículo rige mandato a varias personas. Si el mandato se confiere a varias personas sin estipular expresamente la forma o el orden de su actuación, se entiende que pueden desempeñarse conjun'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato', 'varias', 'personas', 'articulo 1326'], segments: [], amendments: [] },
  { id: 'ccyc-art-1327', lawId: 'codigo-civil-comercial', number: '1327', order: 1327, title: "Sustitución del mandato", text: "Sustitución del mandato. El mandatario puede sustituir en otra persona la ejecución del mandato y es responsable de la elección del sustituto, excepto cuando lo haga por indicación del mandante. En caso de sustitución, el mandante tiene la acción directa contra el sustituto prevista en los artículos 736 y concordantes, pero no está obligado a pagarle retribución si la sustitución no era necesaria. El mandatario responde directamente por la actuación del sustituto cuando no fue autorizado a sustituir, o cuando la sustitución era innecesaria para la ejecución del mandato.", plainLanguageExplanation: "Establece el régimen de sustitución del mandato. El mandatario puede sustituir en otra persona la ejecución del mandato y es responsable de la elección del sustituto, excepto cuando lo haga por indicación del mandante.", practicalEffects: ['En la práctica, este artículo rige sustitución del mandato. El mandatario puede sustituir en otra persona la ejecución del mandato y es responsable de la elección del sustituto, excepto cuando lo haga por indicación del mandante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sustitucin', 'mandato', 'articulo 1327'], segments: [], amendments: [] },
  { id: 'ccyc-art-1328', lawId: 'codigo-civil-comercial', number: '1328', order: 1328, title: "Obligaciones del mandante", text: "Obligaciones del mandante. El mandante está obligado a: a) suministrar al mandatario los medios necesarios para la ejecución del mandato y compensarle, en cualquier momento que le sea requerido, todo gasto razonable en que haya incurrido para ese fin; b) indemnizar al mandatario los daños que sufra como consecuencia de la ejecución del mandato, no imputables al propio mandatario; c) liberar al mandatario de las obligaciones asumidas con terceros, proveyéndole de los medios necesarios para ello; d) abonar al mandatario la retribución convenida. Si el mandato se extingue sin culpa del mandatario, debe la parte de la retribución proporcionada al servicio cumplido; pero si el mandatario ha recibido un adelanto mayor de lo que le corresponde, el mandante no puede exigir su restitución.", plainLanguageExplanation: "Establece el régimen de obligaciones del mandante. El mandante está obligado a: a) suministrar al mandatario los medios necesarios para la ejecución del mandato y compensarle, en cualquier momento que le sea requerido, todo gasto razonable en que haya incurrido para ese fin; b) indemnizar al mandatario los daños que sufra como co", practicalEffects: ['En la práctica, este artículo rige obligaciones del mandante. El mandante está obligado a: a) suministrar al mandatario los medios necesarios para la ejecución del mandato y compensarle, en cualquier momento que'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'mandante', 'articulo 1328'], segments: [], amendments: [] },
  { id: 'ccyc-art-1329', lawId: 'codigo-civil-comercial', number: '1329', order: 1329, title: "Extinción del mandato", text: "Extinción del mandato. El mandato se extingue: a) por el transcurso del plazo por el que fue otorgado, o por el cumplimiento de la condición resolutoria pactada; b) por la ejecución del negocio para el cual fue dado; c) por la revocación del mandante; d) por la renuncia del mandatario; e) por la muerte o incapacidad del mandante o del mandatario.", plainLanguageExplanation: "Establece el régimen de extinción del mandato. El mandato se extingue: a) por el transcurso del plazo por el que fue otorgado, o por el cumplimiento de la condición resolutoria pactada; b) por la ejecución del negocio para el cual fue dado; c) por la revocación del mandante; d) por la renuncia del mandatario; e) por la muerte", practicalEffects: ['En la práctica, este artículo rige extinción del mandato. El mandato se extingue: a) por el transcurso del plazo por el que fue otorgado, o por el cumplimiento de la condición resolutoria pactada; b) por la e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'mandato', 'articulo 1329'], segments: [], amendments: [] },
  { id: 'ccyc-art-1330', lawId: 'codigo-civil-comercial', number: '1330', order: 1330, title: "Mandato irrevocable", text: "Mandato irrevocable. El mandato puede convenirse expresamente como irrevocable en los casos de los incisos b) y c) del artículo 380. El mandato destinado a ejecutarse después de la muerte del mandante es nulo si no puede valer como disposición de última voluntad.", plainLanguageExplanation: "Establece el régimen de mandato irrevocable. El mandato puede convenirse expresamente como irrevocable en los casos de los incisos b) y c) del artículo 380.", practicalEffects: ['En la práctica, este artículo rige mandato irrevocable. El mandato puede convenirse expresamente como irrevocable en los casos de los incisos b) y c) del artículo 380.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato', 'irrevocable', 'articulo 1330'], segments: [], amendments: [] },
  { id: 'ccyc-art-1331', lawId: 'codigo-civil-comercial', number: '1331', order: 1331, title: "Revocación", text: "Revocación. La revocación sin justa causa del mandato otorgado por tiempo o asunto determinado obliga al mandante a indemnizar los daños causados; si el mandato fue dado por plazo indeterminado, el mandante debe dar aviso adecuado a las circunstancias o, en su defecto, indemnizar los daños que cause su omisión.", plainLanguageExplanation: "Establece el régimen de revocación. La revocación sin justa causa del mandato otorgado por tiempo o asunto determinado obliga al mandante a indemnizar los daños causados; si el mandato fue dado por plazo indeterminado, el mandante debe dar aviso adecuado a las circunstancias o, en su defecto, indemnizar los daños q", practicalEffects: ['En la práctica, este artículo rige revocación. La revocación sin justa causa del mandato otorgado por tiempo o asunto determinado obliga al mandante a indemnizar los daños causados; si el mandato f'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocacinarticulo 1331'], segments: [], amendments: [] },
  { id: 'ccyc-art-1332', lawId: 'codigo-civil-comercial', number: '1332', order: 1332, title: "Renuncia", text: "Renuncia. La renuncia intempestiva y sin causa justificada del mandatario obliga a indemnizar los daños que cause al mandante.", plainLanguageExplanation: "Establece el régimen de renuncia. La renuncia intempestiva y sin causa justificada del mandatario obliga a indemnizar los daños que cause al mandante.", practicalEffects: ['En la práctica, este artículo rige renuncia. La renuncia intempestiva y sin causa justificada del mandatario obliga a indemnizar los daños que cause al mandante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['renunciaarticulo 1332'], segments: [], amendments: [] },
  { id: 'ccyc-art-1333', lawId: 'codigo-civil-comercial', number: '1333', order: 1333, title: "Muerte o incapacidad del mandatario y del mandante", text: "Muerte o incapacidad del mandatario y del mandante. Producida la muerte o incapacidad del mandatario, sus herederos, representantes o asistentes que tengan conocimiento del mandato deben dar pronto aviso al mandante y tomar en interés de éste las medidas que sean requeridas por las circunstancias. Si se produce la muerte o incapacidad del mandante, el mandatario debe ejecutar los actos de conservación si hay peligro en la demora, excepto instrucciones expresas en contrario de los herederos o representantes.", plainLanguageExplanation: "Establece el régimen de muerte o incapacidad del mandatario y del mandante. Producida la muerte o incapacidad del mandatario, sus herederos, representantes o asistentes que tengan conocimiento del mandato deben dar pronto aviso al mandante y tomar en interés de éste las medidas que sean requeridas por las circunstancias.", practicalEffects: ['En la práctica, este artículo rige muerte o incapacidad del mandatario y del mandante. Producida la muerte o incapacidad del mandatario, sus herederos, representantes o asistentes que tengan conocimiento del mandato deben dar pronto avis'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['muerte', 'incapacidad', 'mandatario', 'mandante', 'articulo 1333'], segments: [], amendments: [] },
  { id: 'ccyc-art-1334', lawId: 'codigo-civil-comercial', number: '1334', order: 1334, title: "Rendición de cuentas", text: "Rendición de cuentas. La rendición de cuentas por el mandatario debe ser en las condiciones previstas en los artículos 858 y siguientes acompañada de toda la documentación relativa a su gestión. Excepto estipulación en contrario, las cuentas deben rendirse en el domicilio del mandatario y los gastos que generan son a cargo del mandante. CAPITULO 9 Contrato de consignación", plainLanguageExplanation: "Establece el régimen de rendición de cuentas. La rendición de cuentas por el mandatario debe ser en las condiciones previstas en los artículos 858 y siguientes acompañada de toda la documentación relativa a su gestión.", practicalEffects: ['En la práctica, este artículo rige rendición de cuentas. La rendición de cuentas por el mandatario debe ser en las condiciones previstas en los artículos 858 y siguientes acompañada de toda la documentación relativa a su gestión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rendicin', 'cuentas', 'articulo 1334'], segments: [], amendments: [] },
  { id: 'ccyc-art-1335', lawId: 'codigo-civil-comercial', number: '1335', order: 1335, title: "Definición", text: "Definición. Hay contrato de consignación cuando el mandato es sin representación para la venta de cosas muebles. Se le aplican supletoriamente las disposiciones del Capítulo 8 de este Título.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de consignación cuando el mandato es sin representación para la venta de cosas muebles.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de consignación cuando el mandato es sin representación para la venta de cosas muebles.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1335'], segments: [], amendments: [] },
  { id: 'ccyc-art-1336', lawId: 'codigo-civil-comercial', number: '1336', order: 1336, title: "Indivisibilidad", text: "Indivisibilidad. La consignación es indivisible. Aceptada en una parte se considera aceptada en el todo, y dura mientras el negocio no esté completamente concluido.", plainLanguageExplanation: "Establece el régimen de indivisibilidad. La consignación es indivisible.", practicalEffects: ['En la práctica, este artículo rige indivisibilidad. La consignación es indivisible.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indivisibilidadarticulo 1336'], segments: [], amendments: [] },
  { id: 'ccyc-art-1337', lawId: 'codigo-civil-comercial', number: '1337', order: 1337, title: "Efectos", text: "Efectos. El consignatario queda directamente obligado hacia las personas con quienes contrata, sin que éstas tengan acción contra el consignante, ni éste contra aquéllas.", plainLanguageExplanation: "Establece el régimen de efectos. El consignatario queda directamente obligado hacia las personas con quienes contrata, sin que éstas tengan acción contra el consignante, ni éste contra aquéllas.", practicalEffects: ['En la práctica, este artículo rige efectos. El consignatario queda directamente obligado hacia las personas con quienes contrata, sin que éstas tengan acción contra el consignante, ni éste contr'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 1337'], segments: [], amendments: [] },
  { id: 'ccyc-art-1338', lawId: 'codigo-civil-comercial', number: '1338', order: 1338, title: "Obligaciones del consignatario", text: "Obligaciones del consignatario. El consignatario debe ajustarse a las instrucciones recibidas, y es responsable del daño que se siga al consignante por los negocios en los que se haya apartado de esas instrucciones.", plainLanguageExplanation: "Establece el régimen de obligaciones del consignatario. El consignatario debe ajustarse a las instrucciones recibidas, y es responsable del daño que se siga al consignante por los negocios en los que se haya apartado de esas instrucciones.", practicalEffects: ['En la práctica, este artículo rige obligaciones del consignatario. El consignatario debe ajustarse a las instrucciones recibidas, y es responsable del daño que se siga al consignante por los negocios en los que se hay'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'consignatario', 'articulo 1338'], segments: [], amendments: [] },
  { id: 'ccyc-art-1339', lawId: 'codigo-civil-comercial', number: '1339', order: 1339, title: "Plazos otorgados por el consignatario", text: "Plazos otorgados por el consignatario. El consignatario se presume autorizado a otorgar los plazos de pago que sean de uso en la plaza. Si otorga plazos contra las instrucciones del consignante, o por términos superiores a los de uso, está directamente obligado al pago del precio o de su saldo en el momento en que hubiera correspondido.", plainLanguageExplanation: "Establece el régimen de plazos otorgados por el consignatario. El consignatario se presume autorizado a otorgar los plazos de pago que sean de uso en la plaza.", practicalEffects: ['En la práctica, este artículo rige plazos otorgados por el consignatario. El consignatario se presume autorizado a otorgar los plazos de pago que sean de uso en la plaza.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazos', 'otorgados', 'consignatario', 'articulo 1339'], segments: [], amendments: [] },
  { id: 'ccyc-art-1340', lawId: 'codigo-civil-comercial', number: '1340', order: 1340, title: "Crédito otorgado por el consignatario", text: "Crédito otorgado por el consignatario. El consignatario es responsable ante el consignante por el crédito otorgado a terceros sin la diligencia exigida por las circunstancias.", plainLanguageExplanation: "Establece el régimen de crédito otorgado por el consignatario. El consignatario es responsable ante el consignante por el crédito otorgado a terceros sin la diligencia exigida por las circunstancias.", practicalEffects: ['En la práctica, este artículo rige crédito otorgado por el consignatario. El consignatario es responsable ante el consignante por el crédito otorgado a terceros sin la diligencia exigida por las circunstancias.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['crdito', 'otorgado', 'consignatario', 'articulo 1340'], segments: [], amendments: [] },
  { id: 'ccyc-art-1341', lawId: 'codigo-civil-comercial', number: '1341', order: 1341, title: "Prohibición", text: "Prohibición. El consignatario no puede comprar ni vender para sí las cosas comprendidas en la consignación.", plainLanguageExplanation: "Establece el régimen de prohibición. El consignatario no puede comprar ni vender para sí las cosas comprendidas en la consignación.", practicalEffects: ['En la práctica, este artículo rige prohibición. El consignatario no puede comprar ni vender para sí las cosas comprendidas en la consignación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibicinarticulo 1341'], segments: [], amendments: [] },
  { id: 'ccyc-art-1342', lawId: 'codigo-civil-comercial', number: '1342', order: 1342, title: "Retribución del consignatario", text: "Retribución del consignatario. Si la comisión no ha sido convenida, se debe la que sea de uso en el lugar de cumplimiento de la consignación.", plainLanguageExplanation: "Establece el régimen de retribución del consignatario. Si la comisión no ha sido convenida, se debe la que sea de uso en el lugar de cumplimiento de la consignación.", practicalEffects: ['En la práctica, este artículo rige retribución del consignatario. Si la comisión no ha sido convenida, se debe la que sea de uso en el lugar de cumplimiento de la consignación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retribucin', 'consignatario', 'articulo 1342'], segments: [], amendments: [] },
  { id: 'ccyc-art-1343', lawId: 'codigo-civil-comercial', number: '1343', order: 1343, title: "Comisión de garantía", text: "Comisión de garantía. Cuando, además de la retribución ordinaria, el consignatario ha convenido otra llamada 'de garantía', corren por su cuenta los riesgos de la cobranza y queda directamente obligado a pagar al consignante el precio en los plazos convenidos.", plainLanguageExplanation: "Establece el régimen de comisión de garantía. Cuando, además de la retribución ordinaria, el consignatario ha convenido otra llamada 'de garantía', corren por su cuenta los riesgos de la cobranza y queda directamente obligado a pagar al consignante el precio en los plazos convenidos.", practicalEffects: ['En la práctica, este artículo rige comisión de garantía. Cuando, además de la retribución ordinaria, el consignatario ha convenido otra llamada \'de garantía\', corren por su cuenta los riesgos de la cobranza'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comisin', 'garanta', 'articulo 1343'], segments: [], amendments: [] },
  { id: 'ccyc-art-1344', lawId: 'codigo-civil-comercial', number: '1344', order: 1344, title: "Obligación de pagar el precio", text: "Obligación de pagar el precio. Si el consignatario se obliga a pagar el precio en caso de no restituir las cosas en un plazo determinado, el consignante no puede disponer de ellas hasta que le sean restituidas. Los acreedores del consignatario no pueden embargar las cosas consignadas mientras no se haya pagado su precio. CAPITULO 10 Corretaje", plainLanguageExplanation: "Establece el régimen de obligación de pagar el precio. Si el consignatario se obliga a pagar el precio en caso de no restituir las cosas en un plazo determinado, el consignante no puede disponer de ellas hasta que le sean restituidas.", practicalEffects: ['En la práctica, este artículo rige obligación de pagar el precio. Si el consignatario se obliga a pagar el precio en caso de no restituir las cosas en un plazo determinado, el consignante no puede disponer de ellas hasta que le sean restituidas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'pagar', 'precio', 'articulo 1344'], segments: [], amendments: [] },
  { id: 'ccyc-art-1345', lawId: 'codigo-civil-comercial', number: '1345', order: 1345, title: "Definición", text: "Definición. Hay contrato de corretaje cuando una persona, denominada corredor, se obliga ante otra, a mediar en la negociación y conclusión de uno o varios negocios, sin tener relación de dependencia o representación con ninguna de las partes.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de corretaje cuando una persona, denominada corredor, se obliga ante otra, a mediar en la negociación y conclusión de uno o varios negocios, sin tener relación de dependencia o representación con ninguna de las partes.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de corretaje cuando una persona, denominada corredor, se obliga ante otra, a mediar en la negociación y conclusión de uno o varios negoci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1345'], segments: [], amendments: [] },
  { id: 'ccyc-art-1346', lawId: 'codigo-civil-comercial', number: '1346', order: 1346, title: "Conclusión del contrato de corretaje", text: "Conclusión del contrato de corretaje. Sujetos. El contrato de corretaje se entiende concluido, si el corredor está habilitado para el ejercicio profesional del corretaje, por su intervención en el negocio, sin protesta expresa hecha saber al corredor contemporáneamente con el comienzo de su actuación o por la actuación de otro corredor por el otro comitente. Si el comitente es una persona de derecho público, el contrato de corretaje debe ajustarse a las reglas de contratación pertinentes. Pueden actuar como corredores personas humanas o jurídicas.", plainLanguageExplanation: "Establece el régimen de conclusión del contrato de corretaje. Sujetos.", practicalEffects: ['En la práctica, este artículo rige conclusión del contrato de corretaje. Sujetos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conclusin', 'contrato', 'corretaje', 'articulo 1346'], segments: [], amendments: [] },
  { id: 'ccyc-art-1347', lawId: 'codigo-civil-comercial', number: '1347', order: 1347, title: "Obligaciones del corredor", text: "Obligaciones del corredor. El corredor debe: a) asegurarse de la identidad de las personas que intervienen en los negocios en que media y de su capacidad legal para contratar; b) proponer los negocios con exactitud, precisión y claridad, absteniéndose de mencionar supuestos inexactos que puedan inducir a error a las partes; c) comunicar a las partes todas las circunstancias que sean de su conocimiento y que de algún modo puedan influir en la conclusión o modalidades del negocio; d) mantener confidencialidad de todo lo que concierne a negociaciones en las que interviene, la que sólo debe ceder ante requerimiento judicial o de autoridad pública competente; e) asistir, en las operaciones hechas con su intervención, a la firma de los instrumentos conclusivos y a la entrega de los objetos o valores, si alguna de las partes lo requiere; f) guardar muestras de los productos que se negocien con su intervención, mientras subsista la posibilidad de controversia sobre la calidad de lo entregado.", plainLanguageExplanation: "Establece el régimen de obligaciones del corredor. El corredor debe: a) asegurarse de la identidad de las personas que intervienen en los negocios en que media y de su capacidad legal para contratar; b) proponer los negocios con exactitud, precisión y claridad, absteniéndose de mencionar supuestos inexactos que puedan inducir a e", practicalEffects: ['En la práctica, este artículo rige obligaciones del corredor. El corredor debe: a) asegurarse de la identidad de las personas que intervienen en los negocios en que media y de su capacidad legal para contratar; b'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'corredor', 'articulo 1347'], segments: [], amendments: [] },
  { id: 'ccyc-art-1348', lawId: 'codigo-civil-comercial', number: '1348', order: 1348, title: "Prohibición", text: "Prohibición. Está prohibido al corredor: a) adquirir por sí o por interpósita persona efectos cuya negociación le ha sido encargada; b) tener cualquier clase de participación o interés en la negociación o en los bienes comprendidos en ella.", plainLanguageExplanation: "Establece el régimen de prohibición. Está prohibido al corredor: a) adquirir por sí o por interpósita persona efectos cuya negociación le ha sido encargada; b) tener cualquier clase de participación o interés en la negociación o en los bienes comprendidos en ella.", practicalEffects: ['En la práctica, este artículo rige prohibición. Está prohibido al corredor: a) adquirir por sí o por interpósita persona efectos cuya negociación le ha sido encargada; b) tener cualquier clase de pa'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibicinarticulo 1348'], segments: [], amendments: [] },
  { id: 'ccyc-art-1349', lawId: 'codigo-civil-comercial', number: '1349', order: 1349, title: "Garantía y representación", text: "Garantía y representación. El corredor puede: a) otorgar garantía por obligaciones de una o de ambas partes en la negociación en la que actúen; b) recibir de una parte el encargo de representarla en la ejecución del negocio.", plainLanguageExplanation: "Establece el régimen de garantía y representación. El corredor puede: a) otorgar garantía por obligaciones de una o de ambas partes en la negociación en la que actúen; b) recibir de una parte el encargo de representarla en la ejecución del negocio.", practicalEffects: ['En la práctica, este artículo rige garantía y representación. El corredor puede: a) otorgar garantía por obligaciones de una o de ambas partes en la negociación en la que actúen; b) recibir de una parte el encarg'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garanta', 'representacin', 'articulo 1349'], segments: [], amendments: [] },
  { id: 'ccyc-art-1350', lawId: 'codigo-civil-comercial', number: '1350', order: 1350, title: "Comisión", text: "Comisión. El corredor tiene derecho a la comisión estipulada si el negocio se celebra como resultado de su intervención. Si no hay estipulación, tiene derecho a la de uso en el lugar de celebración del contrato o, en su defecto, en el lugar en que principalmente realiza su cometido. A falta de todas ellas, la fija el juez.", plainLanguageExplanation: "Establece el régimen de comisión. El corredor tiene derecho a la comisión estipulada si el negocio se celebra como resultado de su intervención.", practicalEffects: ['En la práctica, este artículo rige comisión. El corredor tiene derecho a la comisión estipulada si el negocio se celebra como resultado de su intervención.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comisinarticulo 1350'], segments: [], amendments: [] },
  { id: 'ccyc-art-1351', lawId: 'codigo-civil-comercial', number: '1351', order: 1351, title: "Intervención de uno o de varios corredores", text: "Intervención de uno o de varios corredores. Si solo interviene un corredor, todas las partes le deben comisión, excepto pacto en contrario o protesta de una de las partes según el artículo 1.346. No existe solidaridad entre las partes respecto del corredor. Si interviene un corredor por cada parte, cada uno de ellos solo tiene derecho a cobrar comisión de su respectivo comitente. En las locaciones de inmuebles la intermediación solo podrá estar a cargo de un profesional matriculado para ejercer el corretaje inmobiliario conforme la legislación local. (Artículo sustituido por art. 12 de la Ley Nº 27.551 B.O. 30/6/2020. Vigencia: a partir del día siguiente al de su publicación en el Boletín Oficial de la República Argentina y serán aplicables para los contratos que se celebren a partir de su entrada en vigencia. Ley N° 27.551 abrogada por art. 249 del Decreto N° 70/2023 B.O. 27/12/2023)", plainLanguageExplanation: "Establece el régimen de intervención de uno o de varios corredores. Si solo interviene un corredor, todas las partes le deben comisión, excepto pacto en contrario o protesta de una de las partes según el artículo 1.346.", practicalEffects: ['En la práctica, este artículo rige intervención de uno o de varios corredores. Si solo interviene un corredor, todas las partes le deben comisión, excepto pacto en contrario o protesta de una de las partes según el artículo 1.346.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intervencin', 'varios', 'corredores', 'articulo 1351'], segments: [], amendments: [] },
  { id: 'ccyc-art-1352', lawId: 'codigo-civil-comercial', number: '1352', order: 1352, title: "Supuestos específicos de obligación de pagar la comisión", text: "Supuestos específicos de obligación de pagar la comisión. Concluido el contrato, la comisión se debe aunque: a) el contrato esté sometido a condición resolutoria y ésta no se cumpla; b) el contrato no se cumpla, se resuelva, se rescinda o medie distracto; c) el corredor no concluya el contrato, si inicia la negociación y el comitente encarga su conclusión a un tercero, o lo concluye por sí en condiciones sustancialmente similares.", plainLanguageExplanation: "Establece el régimen de supuestos específicos de obligación de pagar la comisión. Concluido el contrato, la comisión se debe aunque: a) el contrato esté sometido a condición resolutoria y ésta no se cumpla; b) el contrato no se cumpla, se resuelva, se rescinda o medie distracto; c) el corredor no concluya el contrato, si inicia la negociación y el comitente en", practicalEffects: ['En la práctica, este artículo rige supuestos específicos de obligación de pagar la comisión. Concluido el contrato, la comisión se debe aunque: a) el contrato esté sometido a condición resolutoria y ésta no se cumpla; b) el contrato no se cump'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['supuestos', 'especficos', 'obligacin', 'pagar', 'comisin', 'articulo 1352'], segments: [], amendments: [] },
  { id: 'ccyc-art-1353', lawId: 'codigo-civil-comercial', number: '1353', order: 1353, title: "Supuestos específicos en los que la comisión no se debe", text: "Supuestos específicos en los que la comisión no se debe. La comisión no se debe si el contrato: a) está sometido a condición suspensiva y ésta no se cumple; b) se anula por ilicitud de su objeto, por incapacidad o falta de representación de cualquiera de las partes, o por otra circunstancia que haya sido conocida por el corredor.", plainLanguageExplanation: "Establece el régimen de supuestos específicos en los que la comisión no se debe. La comisión no se debe si el contrato: a) está sometido a condición suspensiva y ésta no se cumple; b) se anula por ilicitud de su objeto, por incapacidad o falta de representación de cualquiera de las partes, o por otra circunstancia que haya sido conocida por el corredor.", practicalEffects: ['En la práctica, este artículo rige supuestos específicos en los que la comisión no se debe. La comisión no se debe si el contrato: a) está sometido a condición suspensiva y ésta no se cumple; b) se anula por ilicitud de su objeto, por incapac'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['supuestos', 'especficos', 'comisin', 'debe', 'articulo 1353'], segments: [], amendments: [] },
  { id: 'ccyc-art-1354', lawId: 'codigo-civil-comercial', number: '1354', order: 1354, title: "Gastos", text: "Gastos. El corredor no tiene derecho a reembolso de gastos, aun cuando la operación encomendada no se concrete, excepto pacto en contrario.", plainLanguageExplanation: "Establece el régimen de gastos. El corredor no tiene derecho a reembolso de gastos, aun cuando la operación encomendada no se concrete, excepto pacto en contrario.", practicalEffects: ['En la práctica, este artículo rige gastos. El corredor no tiene derecho a reembolso de gastos, aun cuando la operación encomendada no se concrete, excepto pacto en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gastosarticulo 1354'], segments: [], amendments: [] },
  { id: 'ccyc-art-1355', lawId: 'codigo-civil-comercial', number: '1355', order: 1355, title: "Normas especiales", text: "Normas especiales. Las reglas de este Capítulo no obstan a la aplicación de las disposiciones de leyes y reglamentos especiales. CAPITULO 11 Depósito SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de normas especiales. Las reglas de este Capítulo no obstan a la aplicación de las disposiciones de leyes y reglamentos especiales.", practicalEffects: ['En la práctica, este artículo rige normas especiales. Las reglas de este Capítulo no obstan a la aplicación de las disposiciones de leyes y reglamentos especiales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'especiales', 'articulo 1355'], segments: [], amendments: [] },
  { id: 'ccyc-art-1356', lawId: 'codigo-civil-comercial', number: '1356', order: 1356, title: "Definición", text: "Definición. Hay contrato de depósito cuando una parte se obliga a recibir de otra una cosa con la obligación de custodiarla y restituirla con sus frutos.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de depósito cuando una parte se obliga a recibir de otra una cosa con la obligación de custodiarla y restituirla con sus frutos.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de depósito cuando una parte se obliga a recibir de otra una cosa con la obligación de custodiarla y restituirla con sus frutos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1356'], segments: [], amendments: [] },
  { id: 'ccyc-art-1357', lawId: 'codigo-civil-comercial', number: '1357', order: 1357, title: "Presunción de onerosidad", text: "Presunción de onerosidad. El depósito se presume oneroso. Si se pacta la gratuidad, no se debe remuneración, pero el depositante debe reembolsar al depositario los gastos razonables en que incurra para la custodia y restitución.", plainLanguageExplanation: "Establece el régimen de presunción de onerosidad. El depósito se presume oneroso.", practicalEffects: ['En la práctica, este artículo rige presunción de onerosidad. El depósito se presume oneroso.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presuncin', 'onerosidad', 'articulo 1357'], segments: [], amendments: [] },
  { id: 'ccyc-art-1358', lawId: 'codigo-civil-comercial', number: '1358', order: 1358, title: "Obligación del depositario", text: "Obligación del depositario. El depositario debe poner en la guarda de la cosa la diligencia que usa para sus cosas o la que corresponda a su profesión. No puede usar las cosas y debe restituirlas, con sus frutos, cuando le sea requerido.", plainLanguageExplanation: "Establece el régimen de obligación del depositario. El depositario debe poner en la guarda de la cosa la diligencia que usa para sus cosas o la que corresponda a su profesión.", practicalEffects: ['En la práctica, este artículo rige obligación del depositario. El depositario debe poner en la guarda de la cosa la diligencia que usa para sus cosas o la que corresponda a su profesión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'depositario', 'articulo 1358'], segments: [], amendments: [] },
  { id: 'ccyc-art-1359', lawId: 'codigo-civil-comercial', number: '1359', order: 1359, title: "Plazo", text: "Plazo. Si se conviene un plazo, se presume que lo es en favor del depositante. Pero si el depósito es gratuito, el depositario puede exigir del depositante, en todo tiempo, que reciba la cosa depositada.", plainLanguageExplanation: "Establece el régimen de plazo. Si se conviene un plazo, se presume que lo es en favor del depositante.", practicalEffects: ['En la práctica, este artículo rige plazo. Si se conviene un plazo, se presume que lo es en favor del depositante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazoarticulo 1359'], segments: [], amendments: [] },
  { id: 'ccyc-art-1360', lawId: 'codigo-civil-comercial', number: '1360', order: 1360, title: "Depósito oneroso", text: "Depósito oneroso. Si el depósito es oneroso, el depositante debe pagar la remuneración establecida para todo el plazo del contrato, excepto pacto en contrario. Si para la conservación de la cosa es necesario hacer gastos extraordinarios, el depositario debe dar aviso inmediato al depositante, y realizar los gastos razonables causados por actos que no puedan demorarse. Estos gastos y los de restitución son por cuenta del depositante.", plainLanguageExplanation: "Establece el régimen de depósito oneroso. Si el depósito es oneroso, el depositante debe pagar la remuneración establecida para todo el plazo del contrato, excepto pacto en contrario.", practicalEffects: ['En la práctica, este artículo rige depósito oneroso. Si el depósito es oneroso, el depositante debe pagar la remuneración establecida para todo el plazo del contrato, excepto pacto en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['depsito', 'oneroso', 'articulo 1360'], segments: [], amendments: [] },
  { id: 'ccyc-art-1361', lawId: 'codigo-civil-comercial', number: '1361', order: 1361, title: "Lugar de restitución", text: "Lugar de restitución. La cosa depositada debe ser restituida en el lugar en que debía ser custodiada.", plainLanguageExplanation: "Establece el régimen de lugar de restitución. La cosa depositada debe ser restituida en el lugar en que debía ser custodiada.", practicalEffects: ['En la práctica, este artículo rige lugar de restitución. La cosa depositada debe ser restituida en el lugar en que debía ser custodiada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lugar', 'restitucin', 'articulo 1361'], segments: [], amendments: [] },
  { id: 'ccyc-art-1362', lawId: 'codigo-civil-comercial', number: '1362', order: 1362, title: "Modalidad de la custodia", text: "Modalidad de la custodia. Si se convino un modo específico de efectuar la custodia y circunstancias sobrevinientes exigen modificarlo, el depositario puede hacerlo, dando aviso inmediato al depositante.", plainLanguageExplanation: "Establece el régimen de modalidad de la custodia. Si se convino un modo específico de efectuar la custodia y circunstancias sobrevinientes exigen modificarlo, el depositario puede hacerlo, dando aviso inmediato al depositante.", practicalEffects: ['En la práctica, este artículo rige modalidad de la custodia. Si se convino un modo específico de efectuar la custodia y circunstancias sobrevinientes exigen modificarlo, el depositario puede hacerlo, dando aviso'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modalidad', 'custodia', 'articulo 1362'], segments: [], amendments: [] },
  { id: 'ccyc-art-1363', lawId: 'codigo-civil-comercial', number: '1363', order: 1363, title: "Persona a quien debe restituirse la cosa", text: "Persona a quien debe restituirse la cosa. La restitución debe hacerse al depositante o a quien éste indique. Si la cosa se deposita también en interés de un tercero, el depositario no puede restituirla sin su consentimiento.", plainLanguageExplanation: "Establece el régimen de persona a quien debe restituirse la cosa. La restitución debe hacerse al depositante o a quien éste indique.", practicalEffects: ['En la práctica, este artículo rige persona a quien debe restituirse la cosa. La restitución debe hacerse al depositante o a quien éste indique.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['persona', 'quien', 'debe', 'restituirse', 'cosa', 'articulo 1363'], segments: [], amendments: [] },
  { id: 'ccyc-art-1364', lawId: 'codigo-civil-comercial', number: '1364', order: 1364, title: "Pérdida de la cosa", text: "Pérdida de la cosa. Si la cosa depositada perece sin culpa del depositario, la pérdida debe ser soportada por el depositante.", plainLanguageExplanation: "Establece el régimen de pérdida de la cosa. Si la cosa depositada perece sin culpa del depositario, la pérdida debe ser soportada por el depositante.", practicalEffects: ['En la práctica, este artículo rige pérdida de la cosa. Si la cosa depositada perece sin culpa del depositario, la pérdida debe ser soportada por el depositante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prdida', 'cosa', 'articulo 1364'], segments: [], amendments: [] },
  { id: 'ccyc-art-1365', lawId: 'codigo-civil-comercial', number: '1365', order: 1365, title: "Prueba del dominio", text: "Prueba del dominio. El depositario no puede exigir que el depositante pruebe ser dueño de la cosa depositada.", plainLanguageExplanation: "Establece el régimen de prueba del dominio. El depositario no puede exigir que el depositante pruebe ser dueño de la cosa depositada.", practicalEffects: ['En la práctica, este artículo rige prueba del dominio. El depositario no puede exigir que el depositante pruebe ser dueño de la cosa depositada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prueba', 'dominio', 'articulo 1365'], segments: [], amendments: [] },
  { id: 'ccyc-art-1366', lawId: 'codigo-civil-comercial', number: '1366', order: 1366, title: "Herederos", text: "Herederos. Los herederos del depositario que de buena fe hayan enajenado la cosa depositada sólo están obligados a restituir al depositante el precio percibido. Si éste no ha sido pagado, deben cederle el correspondiente crédito. SECCION 2ª Depósito irregular", plainLanguageExplanation: "Establece el régimen de herederos. Los herederos del depositario que de buena fe hayan enajenado la cosa depositada sólo están obligados a restituir al depositante el precio percibido.", practicalEffects: ['En la práctica, este artículo rige herederos. Los herederos del depositario que de buena fe hayan enajenado la cosa depositada sólo están obligados a restituir al depositante el precio percibido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['herederosarticulo 1366'], segments: [], amendments: [] },
  { id: 'ccyc-art-1367', lawId: 'codigo-civil-comercial', number: '1367', order: 1367, title: "Efectos", text: "Efectos. Si se entrega una cantidad de cosas fungibles, que no se encuentra en saco cerrado, se transmite el dominio de las cosas aunque el depositante no haya autorizado su uso o lo haya prohibido. El depositario debe restituir la misma calidad y cantidad. Si se entrega una cantidad de cosas fungibles, y el depositario tiene la facultad de servirse de ellas, se aplican las reglas del mutuo. SECCION 3ª Depósito necesario", plainLanguageExplanation: "Establece el régimen de efectos. Si se entrega una cantidad de cosas fungibles, que no se encuentra en saco cerrado, se transmite el dominio de las cosas aunque el depositante no haya autorizado su uso o lo haya prohibido.", practicalEffects: ['En la práctica, este artículo rige efectos. Si se entrega una cantidad de cosas fungibles, que no se encuentra en saco cerrado, se transmite el dominio de las cosas aunque el depositante no haya autorizado su uso o lo haya prohibido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 1367'], segments: [], amendments: [] },
  { id: 'ccyc-art-1368', lawId: 'codigo-civil-comercial', number: '1368', order: 1368, title: "Definición", text: "Definición. Es depósito necesario aquel en que el depositante no puede elegir la persona del depositario por un acontecimiento que lo somete a una necesidad imperiosa, y el de los efectos introducidos en los hoteles por los viajeros.", plainLanguageExplanation: "Establece el régimen de definición. Es depósito necesario aquel en que el depositante no puede elegir la persona del depositario por un acontecimiento que lo somete a una necesidad imperiosa, y el de los efectos introducidos en los hoteles por los viajeros.", practicalEffects: ['En la práctica, este artículo rige definición. Es depósito necesario aquel en que el depositante no puede elegir la persona del depositario por un acontecimiento que lo somete a una necesidad imper'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1368'], segments: [], amendments: [] },
  { id: 'ccyc-art-1369', lawId: 'codigo-civil-comercial', number: '1369', order: 1369, title: "Depósito en hoteles", text: "Depósito en hoteles. El depósito en los hoteles tiene lugar por la introducción en ellos de los efectos de los viajeros, aunque no los entreguen expresamente al hotelero o sus dependientes y aunque aquéllos tengan las llaves de las habitaciones donde se hallen tales efectos.", plainLanguageExplanation: "Establece el régimen de depósito en hoteles. El depósito en los hoteles tiene lugar por la introducción en ellos de los efectos de los viajeros, aunque no los entreguen expresamente al hotelero o sus dependientes y aunque aquéllos tengan las llaves de las habitaciones donde se hallen tales efectos.", practicalEffects: ['En la práctica, este artículo rige depósito en hoteles. El depósito en los hoteles tiene lugar por la introducción en ellos de los efectos de los viajeros, aunque no los entreguen expresamente al hotelero o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['depsito', 'hoteles', 'articulo 1369'], segments: [], amendments: [] },
  { id: 'ccyc-art-1370', lawId: 'codigo-civil-comercial', number: '1370', order: 1370, title: "Responsabilidad", text: "Responsabilidad. El hotelero responde al viajero por los daños y pérdidas sufridos en: a) los efectos introducidos en el hotel; b) el vehículo guardado en el establecimiento, en garajes u otros lugares adecuados puestos a disposición del viajero por el hotelero.", plainLanguageExplanation: "Establece el régimen de responsabilidad. El hotelero responde al viajero por los daños y pérdidas sufridos en: a) los efectos introducidos en el hotel; b) el vehículo guardado en el establecimiento, en garajes u otros lugares adecuados puestos a disposición del viajero por el hotelero.", practicalEffects: ['En la práctica, este artículo rige responsabilidad. El hotelero responde al viajero por los daños y pérdidas sufridos en: a) los efectos introducidos en el hotel; b) el vehículo guardado en el estableci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 1370'], segments: [], amendments: [] },
  { id: 'ccyc-art-1371', lawId: 'codigo-civil-comercial', number: '1371', order: 1371, title: "Eximentes de responsabilidad", text: "Eximentes de responsabilidad. El hotelero no responde si los daños o pérdidas son causados por caso fortuito o fuerza mayor ajena a la actividad hotelera. Tampoco responde por las cosas dejadas en los vehículos de los viajeros.", plainLanguageExplanation: "Establece el régimen de eximentes de responsabilidad. El hotelero no responde si los daños o pérdidas son causados por caso fortuito o fuerza mayor ajena a la actividad hotelera.", practicalEffects: ['En la práctica, este artículo rige eximentes de responsabilidad. El hotelero no responde si los daños o pérdidas son causados por caso fortuito o fuerza mayor ajena a la actividad hotelera.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eximentes', 'responsabilidad', 'articulo 1371'], segments: [], amendments: [] },
  { id: 'ccyc-art-1372', lawId: 'codigo-civil-comercial', number: '1372', order: 1372, title: "Cosas de valor", text: "Cosas de valor. El viajero que lleve consigo efectos de valor superior al que ordinariamente llevan los pasajeros debe hacerlo saber al hotelero y guardarlos en las cajas de seguridad que se encuentren a su disposición en el establecimiento. En este caso, la responsabilidad del hotelero se limita al valor declarado de los efectos depositados.", plainLanguageExplanation: "Establece el régimen de cosas de valor. El viajero que lleve consigo efectos de valor superior al que ordinariamente llevan los pasajeros debe hacerlo saber al hotelero y guardarlos en las cajas de seguridad que se encuentren a su disposición en el establecimiento.", practicalEffects: ['En la práctica, este artículo rige cosas de valor. El viajero que lleve consigo efectos de valor superior al que ordinariamente llevan los pasajeros debe hacerlo saber al hotelero y guardarlos en las c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cosas', 'valor', 'articulo 1372'], segments: [], amendments: [] },
  { id: 'ccyc-art-1373', lawId: 'codigo-civil-comercial', number: '1373', order: 1373, title: "Negativa a recibir", text: "Negativa a recibir. Si los efectos de los pasajeros son excesivamente valiosos en relación con la importancia del establecimiento, o su guarda causa molestias extraordinarias, los hoteleros pueden negarse a recibirlos.", plainLanguageExplanation: "Establece el régimen de negativa a recibir. Si los efectos de los pasajeros son excesivamente valiosos en relación con la importancia del establecimiento, o su guarda causa molestias extraordinarias, los hoteleros pueden negarse a recibirlos.", practicalEffects: ['En la práctica, este artículo rige negativa a recibir. Si los efectos de los pasajeros son excesivamente valiosos en relación con la importancia del establecimiento, o su guarda causa molestias extraordina'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['negativa', 'recibir', 'articulo 1373'], segments: [], amendments: [] },
  { id: 'ccyc-art-1374', lawId: 'codigo-civil-comercial', number: '1374', order: 1374, title: "Cláusulas que reducen la responsabilidad", text: "Cláusulas que reducen la responsabilidad. Excepto lo dispuesto en los artículos 1372 y 1373, toda cláusula que excluya o limite la responsabilidad del hotelero se tiene por no escrita.", plainLanguageExplanation: "Establece el régimen de cláusulas que reducen la responsabilidad. Excepto lo dispuesto en los artículos 1372 y 1373, toda cláusula que excluya o limite la responsabilidad del hotelero se tiene por no escrita.", practicalEffects: ['En la práctica, este artículo rige cláusulas que reducen la responsabilidad. Excepto lo dispuesto en los artículos 1372 y 1373, toda cláusula que excluya o limite la responsabilidad del hotelero se tiene por no escrita.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusulas', 'reducen', 'responsabilidad', 'articulo 1374'], segments: [], amendments: [] },
  { id: 'ccyc-art-1375', lawId: 'codigo-civil-comercial', number: '1375', order: 1375, title: "Establecimientos y locales asimilables", text: "Establecimientos y locales asimilables. Las normas de esta Sección se aplican a los hospitales, sanatorios, casas de salud y deporte, restaurantes, garajes, lugares y playas de estacionamiento y otros establecimientos similares que prestan sus servicios a título oneroso. La eximente prevista en la última frase del artículo 1371 no rige para los garajes, lugares y playas de estacionamiento que prestan sus servicios a título oneroso. SECCION 4ª Casas de depósito", plainLanguageExplanation: "Establece el régimen de establecimientos y locales asimilables. Las normas de esta Sección se aplican a los hospitales, sanatorios, casas de salud y deporte, restaurantes, garajes, lugares y playas de estacionamiento y otros establecimientos similares que prestan sus servicios a título oneroso.", practicalEffects: ['En la práctica, este artículo rige establecimientos y locales asimilables. Las normas de esta Sección se aplican a los hospitales, sanatorios, casas de salud y deporte, restaurantes, garajes, lugares y playas de estacionamien'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['establecimientos', 'locales', 'asimilables', 'articulo 1375'], segments: [], amendments: [] },
  { id: 'ccyc-art-1376', lawId: 'codigo-civil-comercial', number: '1376', order: 1376, title: "Responsabilidad", text: "Responsabilidad. Los propietarios de casas de depósito son responsables de la conservación de las cosas allí depositadas, excepto que prueben que la pérdida, la disminución o la avería ha derivado de la naturaleza de dichas cosas, de vicio propio de ellas o de los de su embalaje, o de caso fortuito externo a su actividad. La tasación de los daños se hace por peritos arbitradores.", plainLanguageExplanation: "Establece el régimen de responsabilidad. Los propietarios de casas de depósito son responsables de la conservación de las cosas allí depositadas, excepto que prueben que la pérdida, la disminución o la avería ha derivado de la naturaleza de dichas cosas, de vicio propio de ellas o de los de su embalaje, o de caso fortui", practicalEffects: ['En la práctica, este artículo rige responsabilidad. Los propietarios de casas de depósito son responsables de la conservación de las cosas allí depositadas, excepto que prueben que la pérdida, la dismin'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 1376'], segments: [], amendments: [] },
  { id: 'ccyc-art-1377', lawId: 'codigo-civil-comercial', number: '1377', order: 1377, title: "Deberes", text: "Deberes. Los propietarios mencionados en el artículo 1376 deben: a) dar recibo por las cosas que les son entregadas para su custodia, en el que se describa su naturaleza, calidad, peso, cantidad o medida; b) permitir la inspección de las cosas recibidas en depósito al depositante y a quien éste indique. CAPITULO 12 Contratos bancarios SECCION 1ª Disposiciones generales Parágrafo 1° Transparencia de las condiciones contractuales", plainLanguageExplanation: "Establece el régimen de deberes. Los propietarios mencionados en el artículo 1376 deben: a) dar recibo por las cosas que les son entregadas para su custodia, en el que se describa su naturaleza, calidad, peso, cantidad o medida; b) permitir la inspección de las cosas recibidas en depósito al depositante y a quien éste indique.", practicalEffects: ['En la práctica, este artículo rige deberes. Los propietarios mencionados en el artículo 1376 deben: a) dar recibo por las cosas que les son entregadas para su custodia, en el que se describa su'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deberesarticulo 1377'], segments: [], amendments: [] },
  { id: 'ccyc-art-1378', lawId: 'codigo-civil-comercial', number: '1378', order: 1378, title: "Aplicación", text: "Aplicación. Las disposiciones relativas a los contratos bancarios previstas en este Capítulo se aplican a los celebrados con las entidades comprendidas en la normativa sobre entidades financieras, y con las personas y entidades públicas y privadas no comprendidas expresamente en esa legislación cuando el Banco Central de la República Argentina disponga que dicha normativa les es aplicable.", plainLanguageExplanation: "Establece el régimen de aplicación. Las disposiciones relativas a los contratos bancarios previstas en este Capítulo se aplican a los celebrados con las entidades comprendidas en la normativa sobre entidades financieras, y con las personas y entidades públicas y privadas no comprendidas expresamente en esa legislac", practicalEffects: ['En la práctica, este artículo rige aplicación. Las disposiciones relativas a los contratos bancarios previstas en este Capítulo se aplican a los celebrados con las entidades comprendidas en la norm'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacinarticulo 1378'], segments: [], amendments: [] },
  { id: 'ccyc-art-1379', lawId: 'codigo-civil-comercial', number: '1379', order: 1379, title: "Publicidad", text: "Publicidad. La publicidad, la propuesta y la documentación contractual deben indicar con precisión y en forma destacada si la operación corresponde a la cartera de consumo o a la cartera comercial, de acuerdo a la clasificación que realiza el Banco Central de la República Argentina. Esa calificación no prevalece sobre la que surge del contrato, ni de la decisión judicial, conforme a las normas de este Código. Los bancos deben informar en sus anuncios, en forma clara, la tasa de interés, gastos, comisiones y demás condiciones económicas de las operaciones y servicios ofrecidos.", plainLanguageExplanation: "Establece el régimen de publicidad. La publicidad, la propuesta y la documentación contractual deben indicar con precisión y en forma destacada si la operación corresponde a la cartera de consumo o a la cartera comercial, de acuerdo a la clasificación que realiza el Banco Central de la República Argentina.", practicalEffects: ['En la práctica, este artículo rige publicidad. La publicidad, la propuesta y la documentación contractual deben indicar con precisión y en forma destacada si la operación corresponde a la cartera d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicidadarticulo 1379'], segments: [], amendments: [] },
  { id: 'ccyc-art-1380', lawId: 'codigo-civil-comercial', number: '1380', order: 1380, title: "Forma", text: "Forma. Los contratos deben instrumentarse por escrito, conforme a los medios regulados por este Código. El cliente tiene derecho a que se le entregue un ejemplar.", plainLanguageExplanation: "Establece el régimen de forma. Los contratos deben instrumentarse por escrito, conforme a los medios regulados por este Código.", practicalEffects: ['En la práctica, este artículo rige forma. Los contratos deben instrumentarse por escrito, conforme a los medios regulados por este Código.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 1380'], segments: [], amendments: [] },
];
